    ('HISP-S 251', 'INTERMEDIATE SPANISH FOR HERITAGE SPEAKERS', '11376', 'Class Status', 'MWF Monday, Wednesday, Friday 9:10 AM–10:00 AM', 'BH 332', 'Israel Herrera', 11, NULL, 'Drill', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'An intermediate language course designed for heritage students, who grew up speaking/hearing Spanish at home or in their communities. Focuses on the practicing of Spanish across modalities, discussing identity aspects, and exploring social and historical context.', ARRAY['IUB GenEd World Language class'], NULL),
