    ('HISP-S 280', 'SPANISH GRAMMAR IN CONTEXT', '4453', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'BH 139', 'Gibran Delgado-Diaz', 1, NULL, 'Drill', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'A topic-based approach to the formal aspects of Spanish grammar. Formal linguistics skills are developed through explicit grammar instruction, the reading of Hispanic texts, and the study of literature and culture through writing and conversation.', ARRAY['Class uses IU eTexts'], NULL),
