    ('HISP-S 281', 'ADVANCED SPANISH FOR HERITAGE SPEAKERS', '11402', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'SY 003', 'Magaly Gastelum', 0, NULL, 'Drill', '3', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'Provides advanced study of Spanish grammar for students who grew up speaking/hearing Spanish at home or in their communities. Seeks to develop knowledge of how Spanish grammar is used distinctly in different situations and understanding of its contextualized social value.', ARRAY[]::TEXT[], NULL),
    ('HISP-S 281', 'ADVANCED SPANISH FOR HERITAGE SPEAKERS', '11403', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'BH 332', 'Magaly Gastelum', 0, NULL, 'Drill', '3', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'Provides advanced study of Spanish grammar for students who grew up speaking/hearing Spanish at home or in their communities. Seeks to develop knowledge of how Spanish grammar is used distinctly in different situations and understanding of its contextualized social value.', ARRAY[]::TEXT[], NULL),
    ('HISP-S 281', 'ADVANCED SPANISH FOR HERITAGE SPEAKERS', '12934', 'Closed', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'PV A203', 'Roberto De Jesus Ortiz Manzanilla', 0, NULL, 'Drill', '3', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'Provides advanced study of Spanish grammar for students who grew up speaking/hearing Spanish at home or in their communities. Seeks to develop knowledge of how Spanish grammar is used distinctly in different situations and understanding of its contextualized social value.', ARRAY[]::TEXT[], NULL),
    ('HISP-S 308', 'COMPOSITION AND CONVERSATION IN SPANISH', '8814', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'ED 1002', 'K. Allen Davis', 3, NULL, 'Discussion', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This content-based course seeks to improve students'' oral and writing skills in Spanish while fostering critical thinking and cultural awareness. The written component includes an analysis of various writing styles: description, narration, exposition, and argumentation. The oral component includes discussions of cultural topics in the Spanish-speaking world.', ARRAY['Class uses IU eTexts'], NULL),
    ('HISP-S 308', 'COMPOSITION AND CONVERSATION IN SPANISH', '9703', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'ED 1002', 'K. Allen Davis', 3, NULL, 'Discussion', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This content-based course seeks to improve students'' oral and writing skills in Spanish while fostering critical thinking and cultural awareness. The written component includes an analysis of various writing styles: description, narration, exposition, and argumentation. The oral component includes discussions of cultural topics in the Spanish-speaking world.', ARRAY['Class uses IU eTexts'], NULL),
    ('HISP-S 308', 'COMPOSITION AND CONVERSATION IN SPANISH', '10336', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'BH 312', 'Israel Herrera', 0, NULL, 'Discussion', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This content-based course seeks to improve students'' oral and writing skills in Spanish while fostering critical thinking and cultural awareness. The written component includes an analysis of various writing styles: description, narration, exposition, and argumentation. The oral component includes discussions of cultural topics in the Spanish-speaking world.', ARRAY['Class uses IU eTexts'], NULL),
    ('HISP-S 309', 'SPANISH WRITING FOR HERITAGE SPEAKERS', '11404', 'Class Status', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'LH 120', 'Leslie Del Carpio', 9, NULL, 'Discussion', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'Facilitates the development of composition and formal oral communication skills in Spanish and is specifically designed for heritage speakers, students who grew up speaking/hearing Spanish at home or in their communities.', ARRAY[]::TEXT[], NULL),
    ('HISP-S 315', 'SPANISH IN THE BUSINESS WORLD', '1956', 'Class Status', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'SY 003', 'Juan Soto Arrivi', 5, NULL, 'Discussion', '3', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'Introduction to the technical language of the business world, with emphasis on problems of vocabulary, style, composition, and translation in the context of Hispanic mores. Intstruction in Spanish.', ARRAY[]::TEXT[], NULL),
    ('HISP-S 322', 'INTRODUCTION TO FILM ANALYSIS IN SPANISH', '11206', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'SY 200', 'Alejandro Mejias-Lopez', 1, NULL, 'Discussion', '3', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'Introduces the formal elements common to cinema and the terms of film analysis in Spanish. Provides a basic understanding of cultural and historical factors that have influenced film production in Latin America and Spain.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
