    ('HISP-S 412', 'SPANISH AMERICA: THE CULTURAL CONTEXT', '11225', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'EP 256', 'Patrick Dove', 9, NULL, 'Discussion', '3', 'ERNIE PYLE HALL', ARRAY[]::TEXT[], 'A course that integrates historical, social, political, and cultural information about Spanish America.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('HISP-S 420', 'MODERN SPANISH-AMERICAN PROSE FICTION', '29527', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'BH 139', 'Anke Birkenmaier', 7, NULL, 'Discussion', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'We read major short stories, essays, and novels asking how writers from Latin America engage with the pressing questions of their time. Beyond magic realism, Latin American writers intervene in political and media revolutions, leading to new roles for the intellectual and the writer as activist, archivist, and performance artist.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('HISP-S 425', 'SPANISH PHONETICS', '5976', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'BH 145', 'Erik Willis', 3, NULL, 'Discussion', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Intensive patterned pronunciation drills and exercises in sound discrimination and transcription, based on detailed articulatory description of standard Spanish of Spain and Latin America. Attendance in language laboratory required.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('HISP-S 431', 'BILINGUALISM AND SPANISH IN THE U.S.', '13487', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'GA 0007', 'Manuel Diaz-Campos', 0, NULL, 'Discussion', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Survey of current issues of bilingualism in the Spanish-speaking world and United States.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Diversity in U.S.'], NULL),
    ('HISP-S 471', 'COLONIALISM TO MODERNISM', '29528', 'Closed', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'BH 140', 'Alejandro Mejias-Lopez', 0, NULL, 'Discussion', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'A study of cultural and literary texts from the colonial, nation-building and modernist periods in Latin America. Taught in Spanish.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
