    ('HISP-S 499', 'HONORS RESEARCH IN SPANISH', '1959', 'Class Status', NULL, NULL, 'Jonathan Risner', 3, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Guided research culminating in an honors thesis under the direction of a faculty member and reviewed by a faculty committee.', ARRAY[]::TEXT[], NULL),
    ('HISP-S 504', 'GRADUATE STUDIES AND PROFESSIONALIZATION', '10173', 'Class Status', 'F Friday 4:20 PM–5:50 PM', 'GA 0009', 'Rhi Johnson', 12, NULL, 'Practicum', '1', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'This course introduces students to tools for the successful completion of a graduate degree. Series I focuses on best practices for completing course work, preparing for preliminary exams, and beginning the dissertation. Series II aids advanced students in the preparation of grants, publications, and a professional career dossier.', ARRAY[]::TEXT[], NULL),
    ('HISP-S 504', 'GRADUATE STUDIES AND PROFESSIONALIZATION', '10174', 'Class Status', 'F Friday 4:20 PM–5:50 PM', 'GA 0011', 'Erik Willis', 16, NULL, 'Practicum', '1', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'This course introduces students to tools for the successful completion of a graduate degree. Series I focuses on best practices for completing course work, preparing for preliminary exams, and beginning the dissertation. Series II aids advanced students in the preparation of grants, publications, and a professional career dossier.', ARRAY[]::TEXT[], NULL),
    ('HISP-S 511', 'SPANISH SYNTACTIC ANALYSIS', '29498', 'Class Status', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'WH 114', 'Patricia Matos Amaral', 8, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Introduction to the analysis of syntactic data. Focus on developing theoretical apparatus required to account for a range of syntactic phenomena in Spanish.', ARRAY[]::TEXT[], NULL),
    ('HISP-S 512', 'THEORY AND CRITICSM', '13490', 'Class Status', 'M Monday 3:55 PM–6:25 PM', 'ED 3004', 'Patrick Dove', 1, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Focuses on major issues in literary theory, with attention to critical trends in the Hispanic world.', ARRAY[]::TEXT[], NULL),
    ('HISP-S 517', 'METHODS OF TEACHING COLLEGE SPANISH', '5992', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'BH 315', 'Laura Gurzynski-Weiss', 13, NULL, 'Discussion', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('HISP-S 558', 'CONQUEST AND COLONIALISM IN LATIN AMERICA', '33623', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'GA 0009', 'Kathleen Myers', 4, NULL, 'Seminar', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Focusing on Spanish colonialism in the Americas from 1492 to 1800, this course studies a wide variety of textual discourses and visual culture that reflect European, indigenous, and afro-descendant cultural production and the shaping of Latin American societies.', ARRAY[]::TEXT[], NULL),
    ('HISP-S 609', 'SPANISH PHONOLOGY II', '29533', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'BH 337', 'Erik Willis', 10, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Course examines issues in Spanish Phonological system based on speech data using instrumental analyses to document/understand the system. Portion of class will review general methods, techniques employed by Laboratory Phonology studies, followed by specific topics in Spanish Phonology. Course may repeat for credit up to nine credits, if topic varies.', ARRAY[]::TEXT[], NULL),
    ('HISP-S 628', 'TOPICS IN EARLY MODERN SPANISH STUDIES', '29541', 'Class Status', 'W Wednesday 3:55 PM–6:25 PM', 'PY 115', 'Steven Wagschal', 5, NULL, 'Seminar', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Topics may explore themes (madness, history of reading practices), theoretical approaches (historiographical accounts, animal studies), questions of genre (the picaresque, the entremés) major works (Don Quijote), authors (María de Zayas). Course may be repeated twice for up to 6 credits when topic varies.', ARRAY[]::TEXT[], NULL),
    ('HISP-S 802', 'M. A. THESIS', '1960', 'Class Status', NULL, NULL, 'Erik Willis', 5, NULL, 'Independent Study', '1–6', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('HISP-S 803', 'INDIV READ SP OR SP AM LIT/LAN', '1961', 'Class Status', NULL, NULL, 'Erik Willis', 10, NULL, 'Readings', '1–6', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('HISP-S 805', 'PH D THESIS', '1962', 'Class Status', NULL, NULL, 'Erik Willis', 7, NULL, 'Independent Study', '1–12', NULL, ARRAY[]::TEXT[], 'Ph.D. thesis - Spanish', ARRAY[]::TEXT[], NULL),
    ('HISP-S 805', 'PH D THESIS', '7014', 'Class Status', NULL, NULL, 'Erik Willis', 15, NULL, 'Independent Study', '1–12', NULL, ARRAY[]::TEXT[], 'Ph.D. thesis - Spanish', ARRAY[]::TEXT[], NULL),
    ('HISP-X 270', 'SERVICE LEARNING IN SPANISH', '8924', 'Class Status', NULL, NULL, 'Jonathan Risner, Israel Herrera', 5, NULL, 'Lecture', '1', NULL, ARRAY[]::TEXT[], 'Allows HISP-S 250 students to apply skills from their classroom language-learning experience to community projects such as teaching basic Spanish and presenting cultural activities to elementary school children.', ARRAY[]::TEXT[], NULL),
    ('HISP-X 272', 'EXPERIENTIAL LEARNING IN PORTUGUESE', '7857', 'Class Status', NULL, NULL, 'Luciana Namorato, Israel Herrera', 10, NULL, 'Internship', '1', NULL, ARRAY[]::TEXT[], 'Enables undergraduates to make intellectual connections between scholarly pursuits and community involvement. Students arrange 1 credit hour of service work on a creative project that benefits a community, or with local or international nonprofit organizations, government agencies, activist groups, or foundations. Requires a reflection paper on the experience.', ARRAY[]::TEXT[], NULL),
    ('HISP-X 370', 'EXPERIENTIAL LEARNING IN SPANISH', '7858', 'Class Status', NULL, NULL, 'Jonathan Risner, Israel Herrera', 27, NULL, 'Internship', '1', NULL, ARRAY[]::TEXT[], 'Enables undergraduates to make intellectual connections between scholarly pursuits and community involvement. Students arrange 1 credit hour of service work on a creative project that benefits a community, or with local or international nonprofit organizations, government agencies, activist groups, or foundations. Requires a reflection paper on the experience.', ARRAY[]::TEXT[], NULL),
    ('HISP-X 398', 'EXPERIENTIAL RESEARCH', '9498', 'Class Status', NULL, NULL, 'Jonathan Risner', 3, NULL, 'Research', '1', NULL, ARRAY[]::TEXT[], 'Provides the opportunity to collaborate with a tenure-track faculty member on a research project. The project, product, and authorship (if applicable), will be determined on a case-by-case basis.', ARRAY[]::TEXT[], NULL),
    ('HISP-X 490', 'INDIVIDUAL READINGS IN HISPANIC STUDIES', '1958', 'Class Status', NULL, NULL, 'Jonathan Risner', 4, NULL, 'Readings', '1–3', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('HISP-X 491', 'INDIVIDUAL READINGS IN CATALAN STUDIES', '4830', 'Class Status', 'MWF Monday, Wednesday, Friday 11:10 AM–12:25 PM', 'ED 1255', 'Nuria Alishio-Caballero', 2, NULL, 'Discussion', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'I Sem., II Sem. May be repeated once with a different topic for a maximum of 6 credit hours in X491 and C494.', ARRAY[]::TEXT[], NULL),
    ('HISP-X 492', 'INDIVIDUAL READINGS IN LUSO-BRAZILIAN LITERATURE', '1909', 'Class Status', NULL, NULL, 'Luciana Namorato', 5, NULL, 'Discussion', '1–3', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('HIST-A 205', 'ASIAN AMERICAN HISTORY', '12209', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'BH 104', 'Ellen Wu', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Examines the history of Asian migration to the United States from the mid-nineteenth century to the present as part of the making of the "Pacific World." Major themes to be explored include community formation, race, citizenship, nation, and transnationalism.', ARRAY['IUB GenEd S&H credit
COLL (CASE) S&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Diversity in U.S.'], NULL),
    ('HIST-A 207', 'INTRODUCTION TO NATIVE AMERICAN HISTORY', '13828', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'WY 005', 'Liza Black', 5, NULL, 'Lecture', '3', 'WYLIE HALL', ARRAY[]::TEXT[], 'This introductory course surveys the history of Native peoples of North America from the earliest times to the present. It seeks to provide students with a broad understanding of Native American history, prepare students for more advanced course work in Native studies, and enhance students'' understanding of colonialism and American history.', ARRAY['IUB GenEd S&H credit
COLL (CASE) S&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Diversity in U.S.'], NULL),
    ('HIST-A 222', 'LAW IN AMERICA', '12210', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'WY 005', 'Amy Ransford', 2, NULL, 'Lecture', '3', 'WYLIE HALL', ARRAY[]::TEXT[], 'This course will examine the American Legal System from the Revolution to the present. It will use trials, judicial opinions, statutes, stories, films, and other materials to study criminal prosecutions, private law suits, constitutional conflicts and other critical parts of the American legal experience. The basic goals of the course are to help students understand why law has had a powerful role in the development of American society and the consequences of the American reliance on law.', ARRAY['IUB GenEd S&H credit
COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('HIST-A 301', 'COLONIAL AMERICA', '13829', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'SE 140', 'Benjamin Irvin', 0, NULL, 'Lecture', '3', 'SWAIN EAST', ARRAY[]::TEXT[], 'Social, cultural, economic, political, and religious developments in colonial America from first contacts between Native Americans and Europeans through the early eighteenth century. Special topics include colonization, migration, slavery, Atlantic trade, and representative government.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('HIST-A 348', 'CIVIL WAR AND RECONSTRUCTION', '14508', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'GA 1134', 'Stephen Andrews', 0, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'The era of the Civil War and its aftermath. Military, political, economic, and social aspects of the coming of the war, the war years, and the "reconstruction" era following the conflict.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('HIST-A 363', 'HOOSIER NATION: INDIANA IN AMERICAN HISTORY', '29592', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'BH 342', 'David Nichols', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Indiana history and life, from early human interactions to our own time. Emphasis on the relationship of distinctive regional traits and challenges to broader transformations in American and global culture.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('HIST-A 383', 'ROCK, HIP HOP, AND REVOLUTION: POPULAR MUSIC IN THE MAKING OF MODERN AMERICA, 1940 TO THE PRESENT', '29596', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'BH 104', 'Michael McGerr', 2, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Role of popular music in the social, cultural, political, economic, and technological history of the modern United States. Examines a broad range of musical cultures including rhythm and blues, country, rock and roll, modern jazz, pop, folk, soul, funk, and hip hop. Focus on role of popular music in shaping democracy and power, including class, gender, race, and generation relations.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('HIST-A 398', 'DISABILITY IN THE UNITED STATES', '29600', 'Class Status', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'SE 105', 'Benjamin Irvin', 1, NULL, 'Lecture', '3', 'SWAIN EAST', ARRAY[]::TEXT[], 'Disability is a nearly universal condition. Everyone becomes disabled if they live long enough. This course explores disability as it has pertained to a variety of institutions, eras, and events in U.S. history, including slavery and emancipation, immigration, the Progressive Era, World Wars I and II, and the Great Depression.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Diversity in U.S.'], NULL),
    ('HIST-B 270', 'INSIDE NAZI GERMANY', '13905', 'Class Status', 'MW Monday, Wednesday 11:35 AM–12:25 PM', 'FA 015', 'Roberta Pergher', 1, 'Lecture', 'Lecture', '3', 'FINE ARTS', ARRAY[]::TEXT[], 'Explores the Nazis'' origins, vision, and appeal, and the path to war and destruction. Examines how far the Nazis were able to revolutionize German society, the nature of Nazi violence, the challenges they posed to the international community, and their ultimate failure and defeat.', ARRAY['IUB GenEd S&H credit
IUB GenEd World Culture credit
COLL (CASE) S&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('HIST-B 270', 'INSIDE NAZI GERMANY', '33987', 'Class Status', 'W Wednesday 3:10 PM–4:00 PM', 'BH 229', 'Roberta Pergher', 1, 'Discussion', 'Lecture', '3', 'FINE ARTS', ARRAY[]::TEXT[], 'Explores the Nazis'' origins, vision, and appeal, and the path to war and destruction. Examines how far the Nazis were able to revolutionize German society, the nature of Nazi violence, the challenges they posed to the international community, and their ultimate failure and defeat.', ARRAY['IUB GenEd S&H credit
