    ('HIST-C 320', 'THE RISE AND FALL OF THE ROMAN REPUBLIC', '11107', 'Class Status', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'FA 102', 'Colin Elliott', 3, NULL, 'Lecture', '3', 'FINE ARTS', ARRAY[]::TEXT[], 'Nearly eight centuries after Rome was founded by outcasts, Julius Caesar was violently murdered by Senators; Rome''s massive Mediterranean empire had become a prize worth killing for. Examination of the chain of events in which Rome ascended to superpower status and subsequently abandoned its Republican constitution in favor of autocracy.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('HIST-C 377', 'GREEK HISTORY: THE PERSIAN WARS TO THE LEGACY OF ALEXANDER', '29594', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'GY 1050', 'Eric Robinson', 4, NULL, 'Lecture', '3', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'A survey of ancient Greek history ranging from the aftermath of the early Fifth century B.C. clash with the Persians and subsequent Athenian Empire to the Hellenistic era initiated by the conquests of Alexander the Great.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('HIST-C 390', 'DECLINE AND FALL OF THE ROMAN EMPIRE', '13836', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'WH 106', 'Daniel Caner', 4, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'The Decline and Fall of the Roman Empire from the Golden Age of the second century A.D. until the collapse of the Roman power in the West (476 A.D.). and the rise of Islam; Christianity and the fate of classical culture in an age of political, social, and religous transformation; the impact of recent arcaheological discoveries on "the fall of Rome" as a historical problem.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('HIST-D 103', 'THE MAKING OF MODERN RUSSIA', '29563', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'WH 009', 'Tatiana Saburova', 0, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Introduction to main events in Russian history from the middle of the nineteenth century to present. Covers the great liberating reforms of Tsar Alexander II, the last tsar, Nicholas II, the revolutionary leader Vladimir Lenin, the brutal tyrant Joseph Stalin, and the last Communist leader Mikhail Gorbachev.', ARRAY['IUB GenEd S&H credit
IUB GenEd World Culture credit
COLL (CASE) S&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('HIST-D 308', 'EMPIRE OF THE TSARS', '13583', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'AC C102', 'Tatiana Saburova', 14, NULL, 'Lecture', '3', 'CEDAR HALL', ARRAY[]::TEXT[], 'Russian empire under Peter the Great, Catherine the Great, Napoleon''s invasion, expansion across Asia into the Americas, nationalism, war and revolution. Other topics include daily life of the common people, gender issues, religion and the emergence of a modern industrial society.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('HIST-D 327', 'THE HABSBURG EMPIRE, 1780-1918: NATION BUILDING AND IMPERIAL DECLINE', '8912', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'BH 340', 'Ke Chin Hsia', 18, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Enlightened despotism; Metternichian system; struggle for German unification; Habsburg culture and civilization. German-Austrian, Hungarian, Czechoslovak, South Slavic, Rumanian, and Polish nationalism. Industrialization; Christian socialism and Austro-Marxism; murder at Sarajevo; destruction of the empire; its legacy to Europe.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('HIST-D 330', 'EASTERN EUROPE:1944-PRESENT', '29589', 'Class Status', 'MW Monday, Wednesday 8:00 AM–9:15 AM', 'BH 206', 'Maria Bucur-Deckard', 13, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Examines origins of communism in Eastern Europe, brutal take-over and Stalinization, attempts to reform communism and ensuing battles for privatization, democratization, and the Wars in Yugoslavia. Looks at political institutions that shaped communist and post-communist Eastern Europe, and important social and cultural developments.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('HIST-G 300', 'ISSUES IN ASIAN HISTORY', '13837', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'WH 002', 'Fei Hsien Wang', 13, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Study and analysis of selected historical issues and problems of limited scope. Topics will vary but usually cut across fields, regions, and period.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('HIST-G 901', 'ADVANCED RESEARCH', '8614', 'Class Status', NULL, NULL, 'Leah Shopkow', 86, NULL, 'Research', '6', NULL, ARRAY[]::TEXT[], 'Available to graduate students who have completed all course requirements for their doctorates, have passed doctoral qualifying examinations, and have the requisite number of degree credit hours, this course provides the advanced research student with a forum for sharing ideas and problems under the supervision of a senior researcher.', ARRAY[]::TEXT[], NULL),
