    ('HIST-H 601', 'INTRODUCTION TO THE PROFESSIONAL STUDY OF HISTORY', '1967', 'Class Status', 'Tu Tuesday 4:20 PM–6:20 PM', 'LH 112', 'Michael Dodson', 10, NULL, 'Seminar', '4', 'LINDLEY HALL', ARRAY[]::TEXT[], 'This introductory course, mandatory for all incoming graduate students, has three main objectives; to socialize graduate students into the demands of the historical profession; to introduce theory and methods of history and historiography; and to introduce fundamental research skills. The course will include readings across multiple methods, approaches and topics and across time and place.', ARRAY[]::TEXT[], NULL),
    ('HIST-H 601', 'INTRODUCTION TO THE PROFESSIONAL STUDY OF HISTORY', '29603', 'Class Status', 'Tu Tuesday 4:20 PM–6:20 PM', 'BH 015', 'Carolina Ortega', 9, NULL, 'Seminar', '4', 'LINDLEY HALL', ARRAY[]::TEXT[], 'This introductory course, mandatory for all incoming graduate students, has three main objectives; to socialize graduate students into the demands of the historical profession; to introduce theory and methods of history and historiography; and to introduce fundamental research skills. The course will include readings across multiple methods, approaches and topics and across time and place.', ARRAY[]::TEXT[], NULL),
    ('HIST-H 620', 'COLLOQUIUM: MODERN WESTERN EUROPEAN HISTORY', '33291', 'Class Status', 'Th Thursday 3:10 PM–5:10 PM', 'BH 219', 'Mark Roseman', 9, NULL, 'Lecture', '4', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'These colloquia are seminar size and involve oral and written study of the problems, bibliographies, interpretations, and research trends in the fields with which they respectively deal; they are the chief means by which a student becomes knowledgeable in history at a professional level and prepares for the doctoral Qualifying Examination.', ARRAY[]::TEXT[], NULL),
    ('HIST-H 645', 'COLLOQ IN EAST EUROPEAN HIST', '29605', 'Class Status', 'W Wednesday 4:20 PM–6:20 PM', 'BH 333', 'Maria Bucur-Deckard', 9, NULL, 'Lecture', '4', 'BALLANTINE HALL', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
