    ('HIST-J 400', 'RESEARCH IN HISTORY', '29601', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'BH 241', 'Leah Shopkow', 7, NULL, 'Seminar', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Develops research skills in history, focusing on the issues and sources of a broad time period and/or theme with multi-national or global scope. Topics vary.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('HIST-J 400', 'RESEARCH IN HISTORY', '31476', 'Class Status', 'M Monday 12:45 PM–3:15 PM', 'BH 338', 'Michael McGerr', 7, NULL, 'Seminar', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Develops research skills in history, focusing on the issues and sources of a broad time period and/or theme with multi-national or global scope. Topics vary.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('HIST-J 425', 'HISTORY CAPSTONE SEMINAR', '32558', 'Class Status', 'M Monday 3:10 PM–5:40 PM', 'BH 217', 'Peter Guardino', 4, NULL, 'Seminar', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Requires research and presentation of a substantial historical project, such as a paper, exhibit, or oral history on a topic chosen by the student.', ARRAY[]::TEXT[], NULL),
    ('HIST-J 425', 'HISTORY CAPSTONE SEMINAR', '14989', 'Closed', 'M Monday 12:45 PM–3:15 PM', 'SY 004', 'Arlene Diaz', 0, NULL, 'Seminar', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Requires research and presentation of a substantial historical project, such as a paper, exhibit, or oral history on a topic chosen by the student.', ARRAY[]::TEXT[], NULL),
    ('HIST-K 392', 'HONORS SEMINAR', '1970', 'Class Status', 'Th Thursday 3:10 PM–5:40 PM', 'BH 245', 'Jonathan Schlesinger', 10, NULL, 'Seminar', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'For honors students only. Introduction to various current approaches in historical scholarship, illustrated with the work of professors in the department.', ARRAY['COLL INTENSIVE WRITING SECTIONS'], NULL),
    ('HIST-K 393', 'READING FOR HONORS', '34464', 'Class Status', NULL, NULL, 'Jonathan Schlesinger', 18, NULL, 'Independent Study', '1–12', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('HIST-K 498', 'SENIOR HONORS PAPER', '34461', 'Class Status', NULL, NULL, 'Jonathan Schlesinger', 14, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Senior-level course for honors students only. Training in research and writing, culminating in an honors paper to be written under direction of a faculty member and reviewed by the director of the History Honors Program.', ARRAY[]::TEXT[], NULL),
    ('HIST-K 499', 'SENIOR HONORS THESIS', '34463', 'Class Status', NULL, NULL, 'Jonathan Schlesinger', 10, NULL, 'Independent Study', '3–6', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('HIST-T 500', 'TOPICS IN HISTORY', '35654', 'Class Status', NULL, 'OL ONLINE', 'Janine Giordano Drake', 1, NULL, 'Lecture', '3', 'Online Class', ARRAY[]::TEXT[], 'Intensive study and analysis of selected historical issues and problems of limited scope from the perspective of social and historical studies. Topics will vary but will ordinarily cut across fields, regions, and periods.', ARRAY[]::TEXT[], NULL),
    ('HIST-T 510', 'HISTORICAL METHODOLOGY', '32757', 'Class Status', NULL, 'OL ONLINE', 'David Parnell', 2, NULL, 'Lecture', '3', 'Online Class', ARRAY[]::TEXT[], 'An intensive, multi-media investigation of what artifacts comprise history and how historians devise various methods of inquiry driven by research questions to explain/interconnect those artifacts. Looks at surveys of current research methods/problems, especially in U.S. history, to illuminate the development of history as a rigorous discipline of inquiry.', ARRAY['Class uses IU eTexts'], NULL),
    ('HIST-T 510', 'HISTORICAL METHODOLOGY', '36639', 'Class Status', NULL, 'OL ONLINE', 'David Parnell', 2, NULL, 'Lecture', '3', 'Online Class', ARRAY[]::TEXT[], 'An intensive, multi-media investigation of what artifacts comprise history and how historians devise various methods of inquiry driven by research questions to explain/interconnect those artifacts. Looks at surveys of current research methods/problems, especially in U.S. history, to illuminate the development of history as a rigorous discipline of inquiry.', ARRAY['Class uses IU eTexts'], NULL),
    ('HIST-T 520', 'TEACHING COLLEGE HISTORY', '35070', 'Class Status', NULL, 'OL ONLINE', 'John Kennedy', 2, NULL, 'Lecture', '3', 'Online Class', ARRAY[]::TEXT[], 'This course prepares high-school teachers to teach college-level history. It contains three aspects: What to teach, how to teach, and how to assess both teaching and learning. The course will contain three aspects: content knowledge of history, the concept and skills of historical thinking, and development of an assessment plan.', ARRAY[]::TEXT[], NULL),
    ('HIST-T 520', 'TEACHING COLLEGE HISTORY', '33227', 'Closed', NULL, 'OL ONLINE', 'Yu Shen', 0, NULL, 'Lecture', '3', 'Online Class', ARRAY[]::TEXT[], 'This course prepares high-school teachers to teach college-level history. It contains three aspects: What to teach, how to teach, and how to assess both teaching and learning. The course will contain three aspects: content knowledge of history, the concept and skills of historical thinking, and development of an assessment plan.', ARRAY[]::TEXT[], NULL),
    ('HIST-T 520', 'TEACHING COLLEGE HISTORY', '34598', 'Closed', NULL, 'OL ONLINE', 'John Kennedy', 0, NULL, 'Lecture', '3', 'Online Class', ARRAY[]::TEXT[], 'This course prepares high-school teachers to teach college-level history. It contains three aspects: What to teach, how to teach, and how to assess both teaching and learning. The course will contain three aspects: content knowledge of history, the concept and skills of historical thinking, and development of an assessment plan.', ARRAY[]::TEXT[], NULL),
    ('HIST-T 530', 'EARLY AMERICA - 1400-1800', '31810', 'Class Status', NULL, 'OL ONLINE', 'Christopher Young', 1, NULL, 'Lecture', '3', 'Online Class', ARRAY[]::TEXT[], 'This course explores the development of North America from 1400 to 1800. Special emphasis will be placed on encounters between natives of the continent and outsiders, the colonial experience, and the causes and consequences of the American Revolution.', ARRAY[]::TEXT[], NULL),
    ('HIST-T 530', 'EARLY AMERICA - 1400-1800', '35870', 'Closed', NULL, 'OL ONLINE', 'Thomas Mason', 0, NULL, 'Lecture', '3', 'Online Class', ARRAY[]::TEXT[], 'This course explores the development of North America from 1400 to 1800. Special emphasis will be placed on encounters between natives of the continent and outsiders, the colonial experience, and the causes and consequences of the American Revolution.', ARRAY[]::TEXT[], NULL),
    ('HIST-T 540', 'THE LONG NINETEENTH CENTURY, 1800-1917', '35466', 'Class Status', NULL, 'OL ONLINE', 'Kevin Moskowitz', 1, NULL, 'Lecture', '3', 'Online Class', ARRAY[]::TEXT[], 'This course tracks U.S. history between the early nineteenth century and American participation in the First World War. Students will articulate their understanding of scholarly books, articles, and original records and will review two books, write short response papers, and craft a historiographical essay on a topic of their choosing.', ARRAY[]::TEXT[], NULL),
    ('HIST-T 540', 'THE LONG NINETEENTH CENTURY, 1800-1917', '37022', 'Class Status', NULL, 'OL ONLINE', 'Kevin Moskowitz', 5, NULL, 'Lecture', '3', 'Online Class', ARRAY[]::TEXT[], 'This course tracks U.S. history between the early nineteenth century and American participation in the First World War. Students will articulate their understanding of scholarly books, articles, and original records and will review two books, write short response papers, and craft a historiographical essay on a topic of their choosing.', ARRAY[]::TEXT[], NULL),
    ('HIST-T 541', 'LATIN AMERICAN HISTORY', '32036', 'Class Status', NULL, 'OL ONLINE', 'Christine Nemcik', 2, NULL, 'Seminar', '3', 'Online Class', ARRAY[]::TEXT[], 'This course provides an introduction to Latin American history. Instructors may choose to provide a broad overview or use a theme as a lens with which to gain an understanding of Latin American history.', ARRAY[]::TEXT[], NULL),
    ('HIST-T 541', 'LATIN AMERICAN HISTORY', '36546', 'Class Status', NULL, 'OL ONLINE', 'Sam Claussen', 8, NULL, 'Seminar', '3', 'Online Class', ARRAY[]::TEXT[], 'This course provides an introduction to Latin American history. Instructors may choose to provide a broad overview or use a theme as a lens with which to gain an understanding of Latin American history.', ARRAY[]::TEXT[], NULL),
    ('HIST-T 541', 'LATIN AMERICAN HISTORY', '34756', 'Closed', NULL, 'OL ONLINE', 'Hayley Froysland', 0, NULL, 'Seminar', '3', 'Online Class', ARRAY[]::TEXT[], 'This course provides an introduction to Latin American history. Instructors may choose to provide a broad overview or use a theme as a lens with which to gain an understanding of Latin American history.', ARRAY[]::TEXT[], NULL),
    ('HIST-T 551', 'ASIAN HISTORY', '33250', 'Class Status', NULL, 'OL ONLINE', 'Yu Shen', 7, NULL, 'Lecture', '3', 'Online Class', ARRAY[]::TEXT[], 'This course covers the histories of China, Japan, and Korea in the late 19th and 20th centuries. It covers the modernization of the three countries, Japanese imperialism, World War II in Asia, Chinese and North Korean communist revolutions, and postwar economy, politics, and society in Japan, South Korea, and China.', ARRAY[]::TEXT[], NULL),
    ('HIST-T 551', 'ASIAN HISTORY', '35014', 'Class Status', NULL, 'OL ONLINE', 'Yu Shen', 3, NULL, 'Lecture', '3', 'Online Class', ARRAY[]::TEXT[], 'This course covers the histories of China, Japan, and Korea in the late 19th and 20th centuries. It covers the modernization of the three countries, Japanese imperialism, World War II in Asia, Chinese and North Korean communist revolutions, and postwar economy, politics, and society in Japan, South Korea, and China.', ARRAY[]::TEXT[], NULL),
    ('HIST-T 560', 'THE UNITED STATES & THE WORLD: COMPARATIVE HISTORY', '32457', 'Closed', NULL, 'OL ONLINE', 'Jonathan Nashel', 0, NULL, 'Lecture', '3', 'Online Class', ARRAY[]::TEXT[], 'History T560 considers themes from the American past connecting it to the wider world. If slavery, for example, is a principal element of our history, how does it compare with the history of other regions? To understand such topics, this course will examine studies in comparative and transnational history.', ARRAY[]::TEXT[], NULL),
    ('HIST-T 560', 'THE UNITED STATES & THE WORLD: COMPARATIVE HISTORY', '34577', 'Closed', NULL, 'OL ONLINE', 'Jonathan Nashel', 0, NULL, 'Lecture', '3', 'Online Class', ARRAY[]::TEXT[], 'History T560 considers themes from the American past connecting it to the wider world. If slavery, for example, is a principal element of our history, how does it compare with the history of other regions? To understand such topics, this course will examine studies in comparative and transnational history.', ARRAY[]::TEXT[], NULL),
    ('HIST-T 570', 'INTRODUCTION TO DIGITAL AND PUBLIC HISTORY', '31911', 'Closed', NULL, 'OL ONLINE', 'Thomas Mackie', 0, NULL, 'Activity', '3', 'Online Class', ARRAY[]::TEXT[], 'Offers a graduate-level introduction to digital and public history. This class will provide you with an introduction to the literature of the fields of digital and public history as well as key theoretical, methodological, and practical, issues and concepts.', ARRAY[]::TEXT[], NULL),
    ('HIST-T 571', 'WORLD HISTORY', '34771', 'Class Status', NULL, 'OL ONLINE', 'Andrew McFarland', 1, NULL, 'Lecture', '3', 'Online Class', ARRAY[]::TEXT[], 'This course provides an introduction to the field of World History. Instructors may choose to provide a broad overview or to use a theme as a lens with which to gain an understanding of world history.', ARRAY[]::TEXT[], NULL),
    ('HIST-T 590', 'RESEARCH SEMINAR IN HISTORY', '31816', 'Class Status', NULL, 'OL ONLINE', 'Diana Chen Lin', 2, NULL, 'Lecture', '3', 'Online Class', ARRAY[]::TEXT[], 'This course serves an intensive historical research and writing seminar that seeks to provide graduate students with the structure and support develop a substantial piece of scholarship. Students will also develop and practice other scholarly skills such oral and written presentations and offering effective and collegial critiques of scholarship.', ARRAY[]::TEXT[], NULL),
    ('HIST-T 590', 'RESEARCH SEMINAR IN HISTORY', '32840', 'Class Status', NULL, 'OL ONLINE', 'Sarah Heath', 7, NULL, 'Lecture', '3', 'Online Class', ARRAY[]::TEXT[], 'This course serves an intensive historical research and writing seminar that seeks to provide graduate students with the structure and support develop a substantial piece of scholarship. Students will also develop and practice other scholarly skills such oral and written presentations and offering effective and collegial critiques of scholarship.', ARRAY[]::TEXT[], NULL),
