    ('HIST-W 201', 'SLAVERY AND UNFREEDOM IN WORLD HISTORY', '35504', 'Class Status', 'MW Monday, Wednesday 4:20 PM–6:50 PM', 'BH 215', 'Pedro Machado', 3, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Slavery and varieties of unfreedom have been common features in the histories of most world societies. This course explores the experiences of slavery in the Americas, Africa, South Asia and elsewhere and challenges students to think beyond the commonly understood plantation model of chattel slavery that marked the American experience.', ARRAY['IUB GenEd S&H credit
IUB GenEd World Culture credit
COLL (CASE) S&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('HIST-W 203', 'WORLD WAR I: GLOBAL WAR', '9438', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'EP 257', 'Ke Chin Hsia', 0, NULL, 'Lecture', '3', 'ERNIE PYLE HALL', ARRAY[]::TEXT[], 'World War I claimed millions of lives and forever changed global political and economic landscapes. Europe''s western front dominates our understandings of the war. Why then, is it called a "world war"? This course considers the war''s global scope through different lenses, including military history, empire, gender, race, and environment.', ARRAY['IUB GenEd S&H credit
IUB GenEd World Culture credit
COLL (CASE) S&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('HIST-W 210', 'GLOBAL SOCCER', '13826', 'Closed', NULL, 'WB WEB', 'Pedro Machado', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'The sport of soccer is used to explore questions of race, gender, ethnicity, class, nationalism and empire; to understand how the "beautiful game" offers an alternative way to study themes such as religious animosities, dictatorship, decolonization and industrialization; and to illuminate the many intersections between the personal and the social, the local and the global.', ARRAY['IUB GenEd S&H credit
IUB GenEd World Culture credit
COLL (CASE) S&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('HIST-W 300', 'ISSUES IN WORLD HISTORY', '34861', 'Class Status', 'MW Monday, Wednesday 3:10 PM–5:40 PM', 'WB WEB', 'Michael Dodson', 1, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Focus on the interrelationship of history, economics, religion, art, and cultures of Eurasia from the second millennium B.C. until modern times, with an emphasis on the interaction between China, Persia, India, and the Mediterranean world.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('HIST-W 300', 'ISSUES IN WORLD HISTORY', '14336', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'BH 139', 'Jennifer Foray', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Focus on the interrelationship of history, economics, religion, art, and cultures of Eurasia from the second millennium B.C. until modern times, with an emphasis on the interaction between China, Persia, India, and the Mediterranean world.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('HIST-X 444', 'HISTORY AT WORK', '12955', 'Closed', 'W Wednesday 4:20 PM–6:00 PM', 'SB 231', 'George Andrei', 0, NULL, 'Activity', '1', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], 'Builds on the skills and assets of a History education through exploring vocational options, using campus career achievement resources, and identifying and assessing personal values, interests, and abilities. Supports the development of strategies and tools for the job market and/or professional/graduate education, as well as for lifelong career planning.', ARRAY['COLL (CASE) Career Readiness 2'], NULL),
    ('HIST-X 473', 'INTERNSHIP FOR HISTORY MAJORS', '37317', 'Class Status', NULL, NULL, 'Will Thompson', 4, NULL, 'Internship', '1–3', NULL, ARRAY[]::TEXT[], 'Provides opportunity to receive academic credit for a part-time or full-time, paid or unpaid internship experience in any professional field. Requires a learning contract, employer evaluations, and faculty-supervised critical reflections relating the internship experience to the competencies gained in the major. Credits based on at least 50 work hours per credit hour.', ARRAY[]::TEXT[], NULL),
    ('HIST-X 490', 'UNDERGRADUATE READINGS IN HISTORY', '37377', 'Closed', NULL, NULL, 'Eric Robinson', 0, NULL, 'Lecture', '1–12', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
