    ('HON-X 298', 'HONORS RESEARCH', '14834', 'Closed', NULL, NULL, 'Ehren Newman', 0, NULL, 'Research', '1.5', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Open to Hutton Honors College students who wish to pursue individual or group research outside of existing departments or departmental courses. May be repeated with a different topic for a maximum of 6 credit hours.', ARRAY[]::TEXT[], NULL),
    ('HPSC-G 901', 'ADVANCED RESEARCH', '2020', 'Class Status', NULL, NULL, 'Jutta Schickore', 6, NULL, 'Research', '6', NULL, ARRAY[]::TEXT[], 'Available to graduate students who have completed all course requirements for their doctorates, have passed doctoral qualifying examinations, and have the requisite number of degree credit hours, this course provides the advanced research student with a forum for sharing ideas and problems under the supervision of a senior researcher.', ARRAY[]::TEXT[], NULL),
    ('HPSC-X 102', 'REVOLUTIONS IN SCIENCE: PLATO TO NATO', '8702', 'Class Status', 'MW Monday, Wednesday 11:35 AM–12:25 PM', 'WY 015', 'Domenico Bertoloni Meli', 8, 'Lecture', 'Lecture', '3', 'WYLIE HALL', ARRAY[]::TEXT[], 'An introduction to the formative steps in the scientific tradition. The course will survey in a chronological sequence aspects of the Aristotelian world view, the Copernican revolution, the mechanical philosophy, the chemical and Darwinian revolution, and the rise of twentieth century science.', ARRAY['IUB GenEd S&H credit
