    ('HPSC-X 104', 'SCIENCE AND CULTURE', '10007', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'LI 028', 'Andrea Sullivan-Clarke', 0, NULL, 'Lecture', '3', 'WELLS LIBRARY', ARRAY[]::TEXT[], 'Studies science as a human activity that both contributes and responds to cultural change. Presents and compares a mix of recent and historical cases, which bring out the complex relations between science and such aspects of culture as the arts, commerce, religion, sports, food, gender, race, and conceptions of human nature.', ARRAY['IUB GenEd S&H credit
COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('HPSC-X 108', 'THE SCIENCE OF SEX AND RACE: THEORIES OF BIOLOGICAL DIFFERENTIATION, 1776 TO THE PRESENT', '29322', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'LH 035', 'Sander Gliboff', 4, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'A survey of the history of diversity in the U.S. from the point of view of the history of science, asking how biologists explained and debated the origins of racial or sexual differences and how the debates reflected the interplay between science and culture.', ARRAY['IUB GenEd S&H credit
COLL (CASE) S&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Diversity in U.S.'], NULL),
    ('HPSC-X 111', 'ETHICAL ISSUES IN BIOLOGICAL AND MEDICAL SCIENCES', '11616', 'Closed', 'MW Monday, Wednesday 5:30 PM–6:45 PM', 'BH 206', 'Zachary Hamby', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Investigation of ethical issues that arise in the biological and medical sciences, the impact of these issues on the behavior of scientists during the conduct of scientific research, and on the role of science in discussions about ethics and public policy. Introduction to major ethical theories and critical reasoning in biological and medical ethics.', ARRAY['IUB GenEd A&H credit
COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('HPSC-X 111', 'ETHICAL ISSUES IN BIOLOGICAL AND MEDICAL SCIENCES', '29319', 'Closed', 'MW Monday, Wednesday 1:30 PM–4:00 PM', 'SY 137', 'Amit Hagar', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Investigation of ethical issues that arise in the biological and medical sciences, the impact of these issues on the behavior of scientists during the conduct of scientific research, and on the role of science in discussions about ethics and public policy. Introduction to major ethical theories and critical reasoning in biological and medical ethics.', ARRAY['IUB GenEd A&H credit
COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('HPSC-X 125', 'CRITICAL MEDICAL HUMANITIES - AN INTRODUCTION', '29320', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–12:05 PM', 'BH 308', 'Leah Savion', 11, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Offers an interdisciplinary and inter-professional approach to the psychological and social effects of illness and treatments as they emerge in patient-doctor interactions, with an integrated model of collaboration between health professionals and patients, emphasizing communication and empathy, and illuminating risk assessment, prevalent misconceptions and biases, and ethical considerations in decision making.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('HPSC-X 200', 'SCIENTIFIC REASONING', '12784', 'Closed', 'MW Monday, Wednesday 5:30 PM–6:45 PM', 'BH 340', 'Rebecca Peng', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Patterns of scientific reasoning presented in a simple form useful to both non-scientists and prospective scientists for understanding and evaluating scientific information of all sorts. Illustrations in the natural, biological, behavioral, and bio-medical sciences are drawn from a wide variety of historical and contemporary sources, including popular magazines and newspapers.', ARRAY['IUB GenEd N&M credit
COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('HPSC-X 205', 'INTRODUCTION TO MEDICAL HIST', '11268', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'WY 115', 'Domenico Bertoloni Meli', 6, NULL, 'Lecture', '3', 'WYLIE HALL', ARRAY[]::TEXT[], NULL, ARRAY['IUB GenEd S&H credit
COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('HPSC-X 206', 'BOOM! WHO''S AFRAID OF NUCLEAR POWER AND RADIATION?', '29321', 'Class Status', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'SW 219', 'Jordi Cat', 9, NULL, 'Lecture', '3', 'SWAIN WEST', ARRAY[]::TEXT[], 'Studies the history of the discovery of radioactivity through the development of the first atomic bomb. Weighs risks and benefits of nuclear power and radioactivity in the age of climate change, alternative power sources and medical technology. Emphasizes the methodological, political, and moral challenges of judging risks and making decisions about human health and environmental safety.', ARRAY['IUB GenEd S&H credit
COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('HPSC-X 333', 'CAPSTONE PROJECT IN HISTORY AND PHILOSOPHY OF SCIENCE AND MEDICINE', '6902', 'Class Status', NULL, 'HD TBA', 'Jutta Schickore', 19, NULL, 'Seminar', '1', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Students must attend at least one talk in the colloquium series and then perform a research project or produce a research paper relevant to the topic of one of the presenters.', ARRAY[]::TEXT[], NULL),
    ('HPSC-X 340', 'SCIENTIFIC METHODS: HOW SCIENCE REALLY WORKS', '15230', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'BH 342', 'Jutta Schickore', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Science is governed by methods: methods for performing experiments, analyzing data, testing hypotheses, and writing scientific papers. This course frames the philosophical and historical debates about scientific methods and introduces the conceptual tools to discuss and reflect on the rules and procedures that make the pursuit of knowledge scientific.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('HPSC-X 392', 'UNDERGRADUATE READINGS IN HISTORY AND PHILOSOPHY OF SCIENCE AND MEDICINE', '2021', 'Class Status', NULL, NULL, 'Jutta Schickore', 10, NULL, 'Readings', '1–5', NULL, ARRAY[]::TEXT[], 'Individualized readings for students in history and philosophy of science.', ARRAY[]::TEXT[], NULL),
    ('HPSC-X 407', 'SURVEY OF HISTORY OF SCIENCE SINCE 1750', '29326', 'Class Status', 'Tu Tuesday 2:20 PM–4:50 PM', 'BH 141', 'Sander Gliboff', 6, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Growth of quantitative methods in physical science and experimental methods in natural history. Gradual separation of science from philosophy and theology.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('HPSC-X 411', 'SCIENCE AND VALUES', '29328', 'Class Status', 'W Wednesday 12:45 PM–3:15 PM', 'BH 237', 'Luis Favela', 4, NULL, 'Seminar', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'The course covers the debates about the view that science is (or ought to be) value-free and the roles that values play (or should play) in science. The course includes historical perspectives, but the emphasis will be on current issues and urgent questions about science in society - questions concerning regulation, responsibility, reliability and sustainability.', ARRAY[]::TEXT[], NULL),
    ('HPSC-X 433', 'CAPSTONE IN SCIENCE LITERACY AND RESPONSIBLE RESEARCH', '8667', 'Class Status', NULL, NULL, 'Jutta Schickore', 10, NULL, 'Independent Study', '3', NULL, ARRAY[]::TEXT[], 'Students select one scientific episode (past or current) related to the student''s major and produce an account that illustrates an important methodological or epistemological issue. The final product will be a research paper or creative activity (e.g. a web-based presentation).', ARRAY[]::TEXT[], NULL),
    ('HPSC-X 501', 'PROFESSIONAL DEVELOPMENT SEMINAR', '37269', 'Closed', 'Tu Tuesday 8:00 AM–9:15 AM', 'BH 333', 'Leah Savion', 0, NULL, 'Seminar', '0.5', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Designed for beginning graduate students, but repeatable for credit, this course addresses some of the practical aspects of professional life in History and Philosophy of Science and related fields. Topics include research tools, grant proposals, presentation skills, research ethics, job applications, teaching, and challenges facing underrepresented groups in the academy.', ARRAY[]::TEXT[], NULL),
    ('HPSC-X 507', 'SURVEY OF HISTORY OF SCIENCE SINCE 1750', '29327', 'Class Status', 'Tu Tuesday 2:20 PM–4:50 PM', 'BH 141', 'Sander Gliboff', 4, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Growth of physical, biological and social sciences during 19th and 20th century. Attention will be paid not only to the scientific contents but to the institutional and social context.', ARRAY[]::TEXT[], NULL),
    ('HPSC-X 511', 'SCIENCE AND VALUES', '29329', 'Class Status', 'W Wednesday 12:45 PM–3:15 PM', 'BH 237', 'Luis Favela', 1, NULL, 'Seminar', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'The course covers the debates about the view that science is (or ought to be) value-free. The course combines historical and systematic perspectives. Topics include: 19th-century ideas about ''pure science'' and scientific freedom, ideals of ''value-free science'' and current debates about the roles values play (or should play) in science.', ARRAY[]::TEXT[], NULL),
    ('HPSC-X 533', 'CASE STUDY', '8267', 'Class Status', NULL, NULL, 'Jutta Schickore', 9, NULL, 'Research', '1', NULL, ARRAY[]::TEXT[], 'Case study to apply skills acquired in core courses.', ARRAY[]::TEXT[], NULL),
    ('HPSC-X 600', 'ADVANCED READINGS COURSE', '6384', 'Class Status', NULL, NULL, 'Jutta Schickore', 4, NULL, 'Readings', '1–4', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('HPSC-X 600', 'ADVANCED READINGS COURSE', '3401', 'Closed', NULL, NULL, 'Jutta Schickore', 0, NULL, 'Readings', '1–4', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('HPSC-X 700', 'MASTERS THESIS', '2022', 'Class Status', NULL, NULL, 'Jutta Schickore', 5, NULL, 'Research', '1–6', NULL, ARRAY[]::TEXT[], 'Students will write a thesis. The topic will be selected in consultation with a faculty advisor.', ARRAY[]::TEXT[], NULL),
    ('HPSC-X 733', 'COLLOQUIUM SERIES', '6903', 'Class Status', NULL, 'HD TBA', 'Jutta Schickore', 15, NULL, 'Seminar', '0.5', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Research presentations by invited guests of the HPSC department, both from IU and from other institutions.', ARRAY[]::TEXT[], NULL),
    ('HPSC-X 800', 'PH D THESIS', '2023', 'Class Status', NULL, NULL, 'Jutta Schickore', 6, NULL, 'Research', '1–12', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('HUBI-B 200', 'THE INTRICATE HUMAN', '5012', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'MO 107', 'Andrew Libby, Farrah Bashey-Visser', 0, 'Lecture', 'Lecture', '4', 'MORRISON HALL', ARRAY[]::TEXT[], 'Interdisciplinary study of the human organism including genetics, metabolism and other aspects of physiology, behavior, culture, and environmental context. Case-based approaches to specific content will reflect faculty expertise, student interests, and current issues in human biology. Emphasis is placed on developing scientific literacy and implementing the scientific method.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('HUBI-B 200', 'THE INTRICATE HUMAN', '5879', 'Class Status', 'Th Thursday 2:20 PM–3:35 PM', 'MO 107', 'Farrah Bashey-Visser, Andrew Libby', 1, 'Laboratory', 'Lecture', '4', 'MORRISON HALL', ARRAY[]::TEXT[], 'Interdisciplinary study of the human organism including genetics, metabolism and other aspects of physiology, behavior, culture, and environmental context. Case-based approaches to specific content will reflect faculty expertise, student interests, and current issues in human biology. Emphasis is placed on developing scientific literacy and implementing the scientific method.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
