    ('HUBI-B 200', 'THE INTRICATE HUMAN', '5014', 'Closed', 'Th Thursday 11:10 AM–12:25 PM', 'MO 107', 'Farrah Bashey-Visser, Andrew Libby', 0, 'Laboratory', 'Lecture', '4', 'MORRISON HALL', ARRAY[]::TEXT[], 'Interdisciplinary study of the human organism including genetics, metabolism and other aspects of physiology, behavior, culture, and environmental context. Case-based approaches to specific content will reflect faculty expertise, student interests, and current issues in human biology. Emphasis is placed on developing scientific literacy and implementing the scientific method.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('HUBI-B 200', 'THE INTRICATE HUMAN', '5015', 'Closed', 'Th Thursday 12:45 PM–2:00 PM', 'MO 107', 'Farrah Bashey-Visser, Andrew Libby', 0, 'Laboratory', 'Lecture', '4', 'MORRISON HALL', ARRAY[]::TEXT[], 'Interdisciplinary study of the human organism including genetics, metabolism and other aspects of physiology, behavior, culture, and environmental context. Case-based approaches to specific content will reflect faculty expertise, student interests, and current issues in human biology. Emphasis is placed on developing scientific literacy and implementing the scientific method.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('HUBI-B 300', 'HUMAN DILEMMAS', '30205', 'Closed', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'MO 107', 'Andrew Libby, Jennifer Cullin', 1, 'Lecture', 'Lecture', '4', 'MORRISON HALL', ARRAY[]::TEXT[], 'Social and ethical consideration of the human condition and of the construction of scientific knowledge through case-based investigation of biological processes integrating multiple disciplinary perspectives. Emphasis is placed on logical interpretation of data and on effective communication of evidence and claims. Specific content will reflect faculty expertise.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
