    ('HUBI-X 371', 'PEER INSTRUCTION IN HUMAN BIOLOGY', '3583', 'Class Status', NULL, NULL, 'Andrew Libby', 6, NULL, 'Lecture', '3', NULL, ARRAY[]::TEXT[], 'Supervised teaching and mentoring experience in an undergraduate Human Biology course.', ARRAY[]::TEXT[], NULL),
    ('HUBI-X 498', 'UNDERGRADUATE RESEARCH IN HUMAN BIOLOGY', '3758', 'Class Status', NULL, NULL, 'Andrew Libby', 9, NULL, 'Research', '1–6', NULL, ARRAY[]::TEXT[], 'Introduction to research methods and scientific investigation in a student''s area of concentration. A student is required to complete a written assignment and present an oral report as evidence of each semester''s work.', ARRAY[]::TEXT[], NULL),
    ('ILS-G 901', 'ADVANCED RESEARCH', '2962', 'Class Status', NULL, NULL, 'Pnina Fichman', 19, NULL, 'Research', '6', NULL, ARRAY[]::TEXT[], 'Available to graduate students who have completed all course requirements for their doctorates, have passed doctoral qualifying examinations, and have the requisite number of degree credit hours, this course provides the advanced research student with a forum for sharing ideas and problems under the supervision of a senior researcher.', ARRAY[]::TEXT[], NULL),
    ('ILS-G 901', 'ADVANCED RESEARCH', '9849', 'Class Status', NULL, NULL, 'Pnina Fichman', 15, NULL, 'Research', '6', NULL, ARRAY[]::TEXT[], 'Available to graduate students who have completed all course requirements for their doctorates, have passed doctoral qualifying examinations, and have the requisite number of degree credit hours, this course provides the advanced research student with a forum for sharing ideas and problems under the supervision of a senior researcher.', ARRAY[]::TEXT[], NULL),
    ('ILS-Z 115', 'FROM JAMES BOND TO ZOMBIE APOCALYPSE AND NSA LEAKS: EVALUATING INFORMATION AND INTELLIGENCE', '8492', 'Class Status', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'IF 1104', 'Carol Choksy', 1, NULL, 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'Using the collection, assessment, analysis, and presentation skills of the intelligence community students will explore important, current policy issues including international relations, privacy, cyber security, war, and humanitarian issues. Students will become familiar with all basic intelligence functions such as the different types of INT: human intelligence, signals intelligence, etc. as well as counterintelligence, hacking, and encryption.', ARRAY[]::TEXT[], NULL),
    ('ILS-Z 331', 'STRATEGIC INTELLIGENCE', '8356', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'IF 1104', 'Carol Choksy', 0, NULL, 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'This class introduces concepts and methods of identifying, collecting, analyzing, and presenting strategic intelligence from perspectives including competitive and strategic military intelligence, globalized crime, government policy, and natural disasters. We examine disruption, networks, systems theory, asymmetric warfare, organizational structure, and information warfare that have impacted modern strategy and strategic intelligence.', ARRAY[]::TEXT[], NULL),
    ('ILS-Z 399', 'TOPICS IN INFORMATION AND LIBRARY SCIENCE', '12369', 'Class Status', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'SW 217', 'Barbara Hillers', 2, NULL, 'Lecture', '3', 'SWAIN WEST', ARRAY[]::TEXT[], 'Study of specific topics in information and library science.', ARRAY[]::TEXT[], NULL),
    ('ILS-Z 410', 'SOCIAL AND ETHICAL IMPACTS OF BIG DATA', '11054', 'Closed', 'MW Monday, Wednesday 9:35 AM–10:55 AM', 'IF 0117', 'Younei Soe', 0, NULL, 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'This course introduces students to new social and ethical challenges arising from the use of data in a broad sense, and the technical and societal approaches to address such challenges. More specifically, this course provides a survey of the social, political, legal, and organizational issues that surround the creation, dissemination, and use of big data from the perspective of social informatics.', ARRAY[]::TEXT[], NULL),
    ('ILS-Z 501', 'USER SERVICES AND TOOLS', '12382', 'Class Status', 'M Monday 3:10 PM–5:40 PM', 'GY 1042', 'Ronald Day', 2, NULL, 'Lecture', '3', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'This course introduces students to the basic information sources and services among different types of libraries and information centers, including academic, public, special and school media.', ARRAY[]::TEXT[], NULL),
    ('ILS-Z 501', 'USER SERVICES AND TOOLS', '12383', 'Closed', 'M Monday 9:35 AM–12:10 PM', 'IF 3111', 'Ronald Day', 0, NULL, 'Lecture', '3', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'This course introduces students to the basic information sources and services among different types of libraries and information centers, including academic, public, special and school media.', ARRAY[]::TEXT[], NULL),
    ('ILS-Z 503', 'REPRESENTATION AND ORGANIZATION', '10018', 'Class Status', 'Th Thursday 4:20 PM–6:50 PM', 'WH 104', 'Rongqian Ma', 7, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Introduces students to common themes in disciplinary approaches to understanding, organizing, representing, and using knowledge and information. Criteria are identified for evaluating and improving ways to organize and represent information for future retrieval using library and information center systems as examples. Emphasis is on concepts and ideas, terminology, and technology.', ARRAY[]::TEXT[], NULL),
    ('ILS-Z 503', 'REPRESENTATION AND ORGANIZATION', '8819', 'Closed', 'Tu Tuesday 9:10 AM–11:40 AM', 'I 232', 'G Arave', 0, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Introduces students to common themes in disciplinary approaches to understanding, organizing, representing, and using knowledge and information. Criteria are identified for evaluating and improving ways to organize and represent information for future retrieval using library and information center systems as examples. Emphasis is on concepts and ideas, terminology, and technology.', ARRAY[]::TEXT[], NULL),
    ('ILS-Z 510', 'INTRODUCTION TO INFORMATION STUDIES', '7010', 'Class Status', 'M Monday 1:55 PM–4:25 PM', 'IF 3111', 'Howard Rosenbaum', 11, NULL, 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'This course surveys the dynamic and shifting information professions, and emerging careers in the information field. Students learn about information architecture, human-computer interaction, information retrieval, data science, and information technology leadership. Issues in information management, user-oriented systems design, socio-technical concepts, and usability are major themes discussed in the course.', ARRAY[]::TEXT[], NULL),
    ('ILS-Z 511', 'DATABASE DESIGN', '14814', 'Class Status', 'W Wednesday 4:20 PM–6:50 PM', 'SE 245', 'Yuerong Hu', 11, NULL, 'Lecture', '3', 'SWAIN EAST', ARRAY[]::TEXT[], 'This course provides students with a deep understanding of various database models, including relational and non-relational databases. Students will learn essential skills such as database modeling, design, implementation, and querying. The final project serves as a capstone, allowing students to apply their knowledge in designing and manipulating real-world databases.', ARRAY[]::TEXT[], NULL),
    ('ILS-Z 511', 'DATABASE DESIGN', '14835', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'IF 1104', 'Carol Choksy', 11, NULL, 'Lecture', '3', 'SWAIN EAST', ARRAY[]::TEXT[], 'This course provides students with a deep understanding of various database models, including relational and non-relational databases. Students will learn essential skills such as database modeling, design, implementation, and querying. The final project serves as a capstone, allowing students to apply their knowledge in designing and manipulating real-world databases.', ARRAY[]::TEXT[], NULL),
    ('ILS-Z 514', 'SOCIAL ASPECTS OF INFORMATION TECHNOLOGY', '29711', 'Class Status', 'W Wednesday 9:10 AM–11:45 AM', 'SY 108', 'Noriko Hara', 8, NULL, 'Lecture', '3', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'This course helps students think critically and constructively about information and communication technology (ICT) and its relationship to work, leisure, and society. It covers concepts and analytical devices as well as empirical case studies related to social consequences of ICT when shaped and used by individuals, public agencies, and businesses.', ARRAY[]::TEXT[], NULL),
    ('ILS-Z 515', 'INFORMATION ARCHITECTURE', '7972', 'Class Status', 'Tu Tuesday 6:40 PM–9:10 PM', 'IF 4063', 'Kate Wehner', 14, NULL, 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('ILS-Z 516', 'HUMAN-COMPUTER INTERACTION', '13535', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:30 PM', 'I 107', 'Younei Soe', 1, NULL, 'Lecture', '3', 'MYLES BRAND HALL', ARRAY[]::TEXT[], 'Examines human factors associated with information technology, provides students with knowledge of the variables likely to influence the perceived usability, and hence the acceptability, of any information technology. In so doing it will enable students to progress further towards specialist''s work in the important field of human-computer interaction.', ARRAY[]::TEXT[], NULL),
    ('ILS-Z 534', 'SEARCH', '29714', 'Class Status', 'Tu Tuesday 12:45 PM–3:15 PM', 'WH 121', 'Ali Ghazinejad', 26, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'This course covers fundamental theories of modern information retrieval (IR) and text mining, focusing on search engines. It introduces IR, Natural Language Processing (NLP), and key mathematical concepts as they relate to the search problem. It then explores classical retrieval models, search engine workings, and advanced text mining topics.', ARRAY[]::TEXT[], NULL),
    ('ILS-Z 543', 'COMPUTER-MEDIATED COMMUNICATN', '29712', 'Class Status', 'Tu Tuesday 5:30 PM–8:00 PM', 'IF 0002', 'Susan Herring', 7, NULL, 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('ILS-Z 550', 'INFORMATION INSTITUTIONS AND THEIR MANAGEMENT', '14175', 'Class Status', 'Th Thursday 4:20 PM–6:50 PM', 'SB 131', 'Megan Vladoiu', 3, NULL, 'Lecture', '3', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], 'Information institutions preserve, conserve, and disseminate information objects. In this course students will learn about libraries, archives, museums, and related organizations, examining their commonalities and differences. Students will study relevant management issues including planning, leading and organizing. They will explore information policies, workflows, ethics, intellectual freedom, laws, and social norms.', ARRAY[]::TEXT[], NULL),
    ('ILS-Z 555', 'STRATEGIC INTELLIGENCE', '8357', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'IF 1104', 'Carol Choksy', 5, NULL, 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('ILS-Z 571', 'MATERIALS FOR YOUTH', '3157', 'Class Status', 'Th Thursday 9:10 AM–11:40 AM', 'WY 111', 'Ginny Hosler, Kate Long', 6, NULL, 'Lecture', '3', 'WYLIE HALL', ARRAY[]::TEXT[], 'An overview of materials for educational, informational, and literary use by children and young adults with an emphasis on critical selection and analysis, knowledge of age-level developmental stages, and motivational techniques. Includes print, film, video and TV, computer software formats.', ARRAY[]::TEXT[], NULL),
    ('ILS-Z 581', 'ARCHIVES AND RECORDS MANAGEMENT', '12084', 'Closed', 'W Wednesday 12:45 PM–3:15 PM', 'IF 0006', 'Devan Donaldson', 0, NULL, 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('ILS-Z 583', 'RARE BOOK LIBRARIANSHIP', '3422', 'Closed', 'Th Thursday 9:10 AM–11:45 AM', 'LL 013', 'Rebecca Baumann', 0, NULL, 'Lecture', '3', 'LILLY LIBRARY', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('ILS-Z 584', 'MANUSCRIPTS', '5274', 'Closed', 'W Wednesday 12:45 PM–3:15 PM', 'LL 105', 'Erika Dowell', 0, NULL, 'Lecture', '3', 'LILLY LIBRARY', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('ILS-Z 601', 'DIRECTED READINGS', '2966', 'Class Status', NULL, NULL, 'Pnina Fichman', 13, NULL, 'Readings', '1–6', NULL, ARRAY[]::TEXT[], 'Readings and study in any area of library or information science. Normally Z 601 is sponsored by a full-time faculty member. Readings shall not duplicate content of any course now in the ILS curriculum. Students may enroll in Z 601 twice in the same semester under different instructors.', ARRAY[]::TEXT[], NULL),
    ('ILS-Z 602', 'DIRECTED RESEARCH', '2964', 'Class Status', NULL, NULL, 'Pnina Fichman', 15, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('ILS-Z 604', 'TOPICS IN LIBRARY AND INFORMATION SCIENCE', '12398', 'Class Status', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'SW 217', 'Barbara Hillers', 5, NULL, 'Lecture', '3', 'SWAIN WEST', ARRAY[]::TEXT[], 'Content and instructors will vary.', ARRAY[]::TEXT[], NULL),
    ('ILS-Z 605', 'INTERNSHIP', '2965', 'Class Status', NULL, NULL, 'Devan Donaldson', 16, NULL, 'Internship', '2–6', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('ILS-Z 605', 'INTERNSHIP', '7011', 'Class Status', NULL, NULL, 'Howard Rosenbaum', 20, NULL, 'Internship', '2–6', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('ILS-Z 622', 'RESOURCES AND SERVICES FOR PEOPLE WITH DISABILITIES', '14174', 'Class Status', 'W Wednesday 3:55 PM–6:25 PM', 'I 232', 'Allan Martell', 17, NULL, 'Lecture', '3', 'MYLES BRAND HALL', ARRAY[]::TEXT[], 'Access to information is essential for sustained independence of people with disabilities. This course studies materials, services, and assistive technologies to support this access.', ARRAY[]::TEXT[], NULL),
    ('ILS-Z 639', 'SOCIAL MEDIA MINING', '8457', 'Class Status', 'F Friday 9:10 AM–11:40 AM', 'I 232', 'Ali Ghazinejad', 5, NULL, 'Lecture', '3', 'MYLES BRAND HALL', ARRAY[]::TEXT[], 'This course provides a graduate-level introduction to social media mining and methods. The course provides hands-on experience mining social data for social meaning extraction (focus on sentiment analysis) using automated methods and machine learning technologies. We will read, discuss, and critique claims and findings from contemporary research related to SMM.', ARRAY[]::TEXT[], NULL),
    ('ILS-Z 639', 'SOCIAL MEDIA MINING', '14728', 'Closed', 'M Monday 1:55 PM–4:25 PM', 'IF 0006', 'Siqi Wu', 0, NULL, 'Lecture', '3', 'MYLES BRAND HALL', ARRAY[]::TEXT[], 'This course provides a graduate-level introduction to social media mining and methods. The course provides hands-on experience mining social data for social meaning extraction (focus on sentiment analysis) using automated methods and machine learning technologies. We will read, discuss, and critique claims and findings from contemporary research related to SMM.', ARRAY[]::TEXT[], NULL),
    ('ILS-Z 652', 'DIGITAL LIBRARIES', '3448', 'Class Status', 'F Friday 9:10 AM–11:45 AM', 'I E150', 'John Walsh', 2, NULL, 'Lecture', '3', 'MYLES BRAND HALL', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('ILS-Z 657', 'DIGITAL HUMANITIES', '14815', 'Closed', 'Tu Tuesday 12:45 PM–3:15 PM', 'WY 115', 'Christina Boyles', 0, NULL, 'Lecture', '3', 'WYLIE HALL', ARRAY[]::TEXT[], 'This course explores uses of information technology in digital humanities (humanities computing) from electronic scholarly editing, to the computational analysis of style, theme, and structure, to the cultural impact of IT on scholarly discourse and publishing. It covers several technologies including extensible Markup Language (XML) and the Text Encoding Initiative.', ARRAY[]::TEXT[], NULL),
    ('ILS-Z 680', 'THE BOOK TO 1450', '14634', 'Class Status', 'F Friday 12:45 PM–3:20 PM', 'LL 105', 'Maureen Maryanski', 3, NULL, 'Lecture', '3', 'LILLY LIBRARY', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('ILS-Z 684', 'DESCRIPTIVE BIBLIOGRAPHY', '2963', 'Class Status', 'Tu Tuesday 9:10 AM–11:45 AM', 'LL 105', 'Joel Silver', 2, NULL, 'Lecture', '3', 'LILLY LIBRARY', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('ILS-Z 690', 'CAPSTONE IN INFORMATION AND LIBRARY SCIENCE', '3712', 'Class Status', NULL, NULL, 'Pnina Fichman', 12, NULL, 'Lecture', '3', NULL, ARRAY[]::TEXT[], 'This course integrates theoretical and practical components of the specialization the student is completing. Working with the specialization director(s), the student will determine the scope and extent of the capstone project and publicly present and defend it upon completion.', ARRAY[]::TEXT[], NULL),
    ('ILS-Z 701', 'INTRODUCTION TO DOCTORAL RESEARCH IN INFORMATION SCIENCE', '35644', 'Class Status', 'Th Thursday 12:45 PM–3:15 PM', 'IF 0002', 'Howard Rosenbaum', 9, 'Lecture', 'Lecture', '6', 'LUDDY HALL', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('ILS-Z 701', 'INTRODUCTION TO DOCTORAL RESEARCH IN INFORMATION SCIENCE', '35645', 'Class Status', 'F Friday 9:30 AM–11:30 AM', 'PY 113', 'Howard Rosenbaum', 9, 'Research', 'Lecture', '6', 'LUDDY HALL', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('ILS-Z 702', 'DOCTORAL RESEARCH PRACTICUM I', '2967', 'Class Status', NULL, NULL, 'Pnina Fichman', 10, NULL, 'Research', '3', NULL, ARRAY[]::TEXT[], 'Student acquires practical hands-on experience with the research process through involvement in a SLIS faculty member''s research project.', ARRAY[]::TEXT[], NULL),
    ('ILS-Z 703', 'DOCTORAL RESEARCH PRACTICUM II', '4272', 'Class Status', NULL, NULL, 'Pnina Fichman', 5, NULL, 'Research', '3', NULL, ARRAY[]::TEXT[], 'Student acquires practical, hands-on experience with the research process through involvement in a ILS faculty member''s research project. The ILS-Z 703 research project should differ substantially from the ILS-Z 702 project with which the student was involved.', ARRAY[]::TEXT[], NULL),
    ('ILS-Z 706', 'INTRODUCTION TO RESEARCH', '29716', 'Class Status', 'Th Thursday 9:10 AM–11:45 AM', 'GY 1032', 'Pnina Fichman', 3, NULL, 'Lecture', '3', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('ILS-Z 710', 'DOCTORAL RESEARCH PRACTICUM III', '3615', 'Class Status', NULL, NULL, 'Pnina Fichman', 10, NULL, 'Research', '3', NULL, ARRAY[]::TEXT[], 'The student applies methods of research under the supervision of an ILS faculty member. The research project may originate with the student or may be one on which the faculty member seeks student assistance.', ARRAY[]::TEXT[], NULL),
    ('ILS-Z 764', 'SEM IN INFORMATION SCIENCE', '12740', 'Class Status', NULL, NULL, 'Pnina Fichman', 13, NULL, 'Lecture', '3', NULL, ARRAY[]::TEXT[], 'A doctoral seminar in IS introduces students to topic areas within the domain of information science (e.g., social informatics, scientometrics, information retrieval, representation and organization of resources, philosophy of information, human computer interaction, visualization). It is a reading-and-writing intensive experience and emphasizes depth over breadth.', ARRAY[]::TEXT[], NULL),
    ('ILS-Z 765', 'DOCTORAL RESEARCH IN INFORMATION SCIENCE', '5385', 'Class Status', NULL, NULL, 'Pnina Fichman', 10, NULL, 'Independent Study', '1–6', NULL, ARRAY[]::TEXT[], 'Independent research or study.', ARRAY[]::TEXT[], NULL),
    ('ILS-Z 790', 'DISSERTATION PROPOSAL IN INFORMATION SCIENCE', '3363', 'Class Status', NULL, NULL, 'Pnina Fichman', 10, NULL, 'Lecture', '3', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('ILS-Z 799', 'PH D THESIS', '2968', 'Class Status', NULL, NULL, 'Pnina Fichman', 47, NULL, 'Independent Study', '1–15', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('IMP-I 470', 'INDIVIDUALIZED MAJOR PROGRAM SENIOR CAPSTONE SEMINAR', '1362', 'Class Status', 'Th Thursday 7:20 PM–9:05 PM', 'WB WEB', 'Mia Ranard', 10, NULL, 'Seminar', '1', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Through presentations and discussion, students prepare final projects for oral reveiew with faculty committees. Students refine retrospective statements through peer-editing and conferences with instructor.', ARRAY[]::TEXT[], NULL),
    ('IMP-X 390', 'INDIVIDUAL MAJOR PROGRAM, READINGS AND RESEARCH', '1361', 'Class Status', NULL, NULL, 'Mia Ranard', 29, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Individual instruction varies but must be directly applicable to a student''s chosen IMP major. Each enrollment is subject to IMP approval.', ARRAY[]::TEXT[], NULL),
    ('IMP-X 473', 'INDIVIDUALIZED MAJOR PROGRAM INTERNSHIP', '7227', 'Class Status', NULL, NULL, 'Mia Ranard', 25, NULL, 'Internship', '1–6', NULL, ARRAY[]::TEXT[], 'Internship experience related to the student''s individualized major. Internship details (supervisor''s name and contact information, duties, hours per week, length of internship) must be provided by the prospective intern and confirmed by IMP prior to enrollment. Weekly written updates required.', ARRAY[]::TEXT[], NULL),
    ('IMP-X 490', 'INDIVIDUAL MAJOR PROGRAM, READINGS AND RESEARCH', '7228', 'Class Status', NULL, NULL, 'Mia Ranard', 44, NULL, 'Readings', '1–15', NULL, ARRAY[]::TEXT[], 'Individual instruction varies but must be directly applicable to a student''s chosen IMP major.', ARRAY[]::TEXT[], NULL),
    ('INFO-G 599', 'THESIS RESEARCH', '3214', 'Class Status', NULL, NULL, 'Gabriele Guidi', 10, NULL, 'Research', '0', NULL, ARRAY[]::TEXT[], 'Master''s students who have enrolled in 30 or more hours of graduate course work applicable to the degree and who have completed all other requirements of the degree except the thesis of final project of performance may enroll in G599. Requires section authorization.', ARRAY[]::TEXT[], NULL),
    ('INFO-G 599', 'THESIS RESEARCH', '3589', 'Class Status', NULL, NULL, 'Gabriele Guidi', 10, NULL, 'Research', '0', NULL, ARRAY[]::TEXT[], 'Master''s students who have enrolled in 30 or more hours of graduate course work applicable to the degree and who have completed all other requirements of the degree except the thesis of final project of performance may enroll in G599. Requires section authorization.', ARRAY[]::TEXT[], NULL),
    ('INFO-G 901', 'ADVANCED RESEARCH', '4253', 'Class Status', NULL, NULL, 'Gabriele Guidi', 18, NULL, 'Research', '6', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Available to graduate students who have completed all course requirements for their doctorates, have passed doctoral qualifying examinations, and have the requisite number of degree credit hours, this course provides the advanced research students with a forum for sharing ideas and problems under the supervision of a senior researcher.', ARRAY[]::TEXT[], NULL),
    ('INFO-G 901', 'ADVANCED RESEARCH', '9846', 'Class Status', NULL, 'WB WEB', 'Gabriele Guidi, Joshua Kemp', 18, NULL, 'Research', '6', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Available to graduate students who have completed all course requirements for their doctorates, have passed doctoral qualifying examinations, and have the requisite number of degree credit hours, this course provides the advanced research students with a forum for sharing ideas and problems under the supervision of a senior researcher.', ARRAY[]::TEXT[], NULL),
    ('INFO-H 494', 'DESIGN AND DEVELOPMENT OF AN INFORMATION SYSTEM', '12027', 'Closed', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'IF 0002', 'LJ Paul', 0, NULL, 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'Honors version of INFO-I 494. Students work on capstone projects in supervised teams. They select an appropriate project (preferably based on cognate) and then learn to develop a plan that leads to success. Teamwork, communication, and organizational skills are emphasized in a real-world-style environment.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 101', 'INTRODUCTION TO INFORMATICS', '4407', 'Class Status', 'Tu Tuesday 3:55 PM–5:15 PM', 'EP 257', 'Alexis Peirce Caudell', 4, 'Lecture', 'Lecture', '4', 'ERNIE PYLE HALL', ARRAY[]::TEXT[], 'Problem solving with information technology; introduction to information representation, relational databases, system design, propositional logic, cutting edge technologies; CPU, operating systems, networks; laboratory emphasizing information technology including webpage design, word processing, and databases using tools available on campus.', ARRAY['IUB GenEd N&M credit'], NULL),
