    ('INFO-I 101', 'INTRODUCTION TO INFORMATICS', '4406', 'Closed', 'M Monday 12:45 PM–2:00 PM', 'IF 1106', 'Katie Siek', 0, 'Lecture', 'Lecture', '4', 'ERNIE PYLE HALL', ARRAY[]::TEXT[], 'Problem solving with information technology; introduction to information representation, relational databases, system design, propositional logic, cutting edge technologies; CPU, operating systems, networks; laboratory emphasizing information technology including webpage design, word processing, and databases using tools available on campus.', ARRAY['IUB GenEd N&M credit'], NULL),
    ('INFO-I 123', 'DATA FLUENCY', '34690', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'GA 1106', 'Samantha Wood', 2, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Data is big. Data is everywhere. How can we possibly be expected to keep up in a world full of data, much of which is data about ourselves? This class provides fundamental skills for the 21st century: understanding data, extracting knowledge from data, generating predictions from data and presenting data.', ARRAY['IUB GenEd N&M credit'], NULL),
    ('INFO-I 123', 'DATA FLUENCY', '34691', 'Class Status', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'IF 0117', 'Jeffery Shih-Chieh Wang', 2, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Data is big. Data is everywhere. How can we possibly be expected to keep up in a world full of data, much of which is data about ourselves? This class provides fundamental skills for the 21st century: understanding data, extracting knowledge from data, generating predictions from data and presenting data.', ARRAY['IUB GenEd N&M credit'], NULL),
    ('INFO-I 130', 'INTRODUCTION TO CYBERSECURITY', '3375', 'Class Status', 'W Wednesday 2:20 PM–3:35 PM', 'I E130', 'Farnaz Asrari', 31, NULL, 'Lecture', '1', 'MYLES BRAND HALL', ARRAY[]::TEXT[], 'This course introduces students to Cybersecurity. The course will primarily focus on introduction to three core areas (technical aspects of security, organizational aspects of security, and legal aspects of security). Through examples of security problems in real life, this course will illuminate fundamental ideas and concepts of information security.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 130', 'INTRODUCTION TO CYBERSECURITY', '6738', 'Class Status', 'W Wednesday 2:20 PM–3:35 PM', 'I E130', 'Farnaz Asrari', 31, NULL, 'Lecture', '1', 'MYLES BRAND HALL', ARRAY[]::TEXT[], 'This course introduces students to Cybersecurity. The course will primarily focus on introduction to three core areas (technical aspects of security, organizational aspects of security, and legal aspects of security). Through examples of security problems in real life, this course will illuminate fundamental ideas and concepts of information security.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 201', 'MATHEMATICAL FOUNDATIONS OF INFORMATICS', '2027', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'LU 1001', 'Filippo Radicchi', 1, 'Lecture', 'Lecture', '4', 'LUDDY CENTER FOR AI', ARRAY[]::TEXT[], 'An introduction to methods of analytical, abstract and critical thinking, deductive reasoning; and logical and mathematical tools used in information sciences. Topics include propositional and predicate logic, natural deduction proof system, sets, functions and relations, proof methods in mathematics, mathematical induction, and graph theory.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 201', 'MATHEMATICAL FOUNDATIONS OF INFORMATICS', '4249', 'Class Status', 'F Friday 1:55 PM–2:45 PM', 'I 107', 'Staff', 4, 'Discussion', 'Lecture', '4', 'LUDDY CENTER FOR AI', ARRAY[]::TEXT[], 'An introduction to methods of analytical, abstract and critical thinking, deductive reasoning; and logical and mathematical tools used in information sciences. Topics include propositional and predicate logic, natural deduction proof system, sets, functions and relations, proof methods in mathematics, mathematical induction, and graph theory.', ARRAY[]::TEXT[], NULL),
