    ('INFO-I 201', 'MATHEMATICAL FOUNDATIONS OF INFORMATICS', '6565', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'IF 0117', 'Alexander Hayes', 7, 'Lecture', 'Lecture', '4', 'LUDDY CENTER FOR AI', ARRAY[]::TEXT[], 'An introduction to methods of analytical, abstract and critical thinking, deductive reasoning; and logical and mathematical tools used in information sciences. Topics include propositional and predicate logic, natural deduction proof system, sets, functions and relations, proof methods in mathematics, mathematical induction, and graph theory.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 202', 'SOCIAL INFORMATICS', '6566', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'GA 1128', 'Jennifer Terrell', 0, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Introduction to key social research perspectives and literatures on the use of information and communication technologies. Discusses current topics such as information ethics, relevant frameworks, popular and controversial uses of technology (e.g., peer-to-peer file sharing), digital divides, etc. Outlines research methodologies for social informatics.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 202', 'SOCIAL INFORMATICS', '10020', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'GA 1118', 'Jennifer Terrell', 0, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Introduction to key social research perspectives and literatures on the use of information and communication technologies. Discusses current topics such as information ethics, relevant frameworks, popular and controversial uses of technology (e.g., peer-to-peer file sharing), digital divides, etc. Outlines research methodologies for social informatics.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 210', 'INFORMATION INFRASTRUCTURE I', '2029', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'LU 1001', 'Shabnam Kavousian, Forum Modi', 2, 'Lecture', 'Lecture', '4', 'LUDDY CENTER FOR AI', ARRAY[]::TEXT[], 'This course introduces software architectures of information systems and basic concepts and procedures of system and application development. Course topics include PHP programming syntax; procedural programming fundamentals; principles of developing dynamic, database-driven applications for the World Wide Web; relational database concepts; and basic MySQL statements.', ARRAY[]::TEXT[], NULL),
