    ('INFO-I 211', 'INFORMATION INFRASTRUCTURE II', '6481', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'SB 015', 'Erika Lee', 4, 'Lecture', 'Lecture', '4', 'LUDDY HALL', ARRAY[]::TEXT[], 'The systems architecture of distributed applications. Advanced programming, including an introduction to the programming of graphical systems.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 211', 'INFORMATION INFRASTRUCTURE II', '36741', 'Class Status', 'F Friday 2:20 PM–3:35 PM', 'BH 108', 'Erika Lee', 4, 'Laboratory', 'Lecture', '4', 'LUDDY HALL', ARRAY[]::TEXT[], 'The systems architecture of distributed applications. Advanced programming, including an introduction to the programming of graphical systems.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 211', 'INFORMATION INFRASTRUCTURE II', '3690', 'Closed', 'Th Thursday 2:20 PM–3:35 PM', 'BH 108', 'Staff', 0, 'Laboratory', 'Lecture', '4', 'LUDDY HALL', ARRAY[]::TEXT[], 'The systems architecture of distributed applications. Advanced programming, including an introduction to the programming of graphical systems.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 211', 'INFORMATION INFRASTRUCTURE II', '4732', 'Closed', 'Th Thursday 3:55 PM–5:10 PM', 'BH 108', 'Staff', 0, 'Laboratory', 'Lecture', '4', 'LUDDY HALL', ARRAY[]::TEXT[], 'The systems architecture of distributed applications. Advanced programming, including an introduction to the programming of graphical systems.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 211', 'INFORMATION INFRASTRUCTURE II', '29435', 'Closed', 'F Friday 9:35 AM–10:50 AM', 'FA 215', 'Erika Lee', 0, 'Laboratory', 'Lecture', '4', 'LUDDY HALL', ARRAY[]::TEXT[], 'The systems architecture of distributed applications. Advanced programming, including an introduction to the programming of graphical systems.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 222', 'THE INFORMATION SOCIETY', '10022', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'IF 1106', 'Nathan Ensmenger', 55, NULL, 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'In this course, students will learn to think critically about what it means to live in an "Information Society." From printing press to telephone to computer to the Internet, they will explore the history and social implications of the various information revolutions that shaped contemporary commercial, scientific, organizational, political life.', ARRAY['IUB GenEd S&H credit'], NULL),
    ('INFO-I 230', 'ANALYTICAL FOUNDATIONS OF SECURITY', '6725', 'Closed', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'GA 1128', 'Kurt Seiffert', 0, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'This course will allow students to re-evaluate and conceptualize material learned in discrete courses to consider the topics from the perspective of security. For example, computer system basics such as hardware (CPU, memory, ...) and software are reconsidered from the perspective of how their interactions create vulnerabilities. Vulnerabilities that combine standard hardware and software configurations will be examined, as these illuminate both security and computer networks. Operating systems and file systems are examined from the perspective of access control, permissions and availability of system services, etc.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 245', 'INTERACTION DESIGN THINKING', '12029', 'Class Status', 'TuTh Tuesday, Thursday 5:30 PM–6:45 PM', 'IF 0117', 'Shunying Blevis', 13, NULL, 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'This hands-on, project driven course offers a creative approach to the process of designing interactive systems. Activities include researching user behaviors, preferences, and needs and then producing sketches, models, and prototypes to explore possible solutions. Resulting designs are desirable to users, technically feasible, and economically viable.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 300', 'HUMAN-COMPUTER INTERACTION DESIGN AND PROGRAMMING', '6681', 'Class Status', 'MW Monday, Wednesday 5:30 PM–6:45 PM', 'IF 0117', 'Jacob Boss', 13, NULL, 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'An intermediate course that teaches students how to assess the usability of software through quantitative and qualitative methods, including conducting task analyses, usability studies, heuristic inspections, interviews, surveys, and focus groups. The course also introduces students to the tool and techniques for designing and testing user interfaces based on a human-centered methodology.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 300', 'HUMAN-COMPUTER INTERACTION DESIGN AND PROGRAMMING', '6915', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'I E130', 'Shunying Blevis', 19, NULL, 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'An intermediate course that teaches students how to assess the usability of software through quantitative and qualitative methods, including conducting task analyses, usability studies, heuristic inspections, interviews, surveys, and focus groups. The course also introduces students to the tool and techniques for designing and testing user interfaces based on a human-centered methodology.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 300', 'HUMAN-COMPUTER INTERACTION DESIGN AND PROGRAMMING', '11055', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:05 PM', 'I E150', 'Shunying Blevis', 17, NULL, 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'An intermediate course that teaches students how to assess the usability of software through quantitative and qualitative methods, including conducting task analyses, usability studies, heuristic inspections, interviews, surveys, and focus groups. The course also introduces students to the tool and techniques for designing and testing user interfaces based on a human-centered methodology.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 300', 'HUMAN-COMPUTER INTERACTION DESIGN AND PROGRAMMING', '6914', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'I E150', 'James Clawson', 0, NULL, 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'An intermediate course that teaches students how to assess the usability of software through quantitative and qualitative methods, including conducting task analyses, usability studies, heuristic inspections, interviews, surveys, and focus groups. The course also introduces students to the tool and techniques for designing and testing user interfaces based on a human-centered methodology.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 301', 'PRESENTATIONS FOR IT PROFESSIONALS', '29681', 'Class Status', 'MW Monday, Wednesday 11:10 AM–1:40 PM', 'I E130', 'Kate Muehlhaus', 7, NULL, 'Lecture', '3', 'MYLES BRAND HALL', ARRAY[]::TEXT[], 'Students present several different types of presentations and engage in developing these "21st Century skills" for their future. The course utilizes an open studio format that allows students to explore public speaking to better prepare for future educational and professional presentations.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 301', 'PRESENTATIONS FOR IT PROFESSIONALS', '14537', 'Closed', 'MW Monday, Wednesday 11:10 AM–1:40 PM', 'I E130', 'Kate Muehlhaus', 0, NULL, 'Lecture', '3', 'MYLES BRAND HALL', ARRAY[]::TEXT[], 'Students present several different types of presentations and engage in developing these "21st Century skills" for their future. The course utilizes an open studio format that allows students to explore public speaking to better prepare for future educational and professional presentations.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 304', 'INTRODUCTION VIRTUAL REALITY', '10024', 'Closed', 'MW Monday, Wednesday 5:30 PM–6:45 PM', 'SB 015', 'Zack Hegarty', 0, NULL, 'Lecture', '3', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], 'Virtual Reality has applications in fields as diverse as medicine, education, military training, trauma recovery, and artificial intelligence. In this course, students will learn the foundational skills needed to build virtual reality applications. We will focus on software programs for building virtual assets and realistic virtual environments.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 308', 'INFORMATION REPRESENTATION', '2034', 'Class Status', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'I E150', 'Daniel Pierz', 21, NULL, 'Lecture', '3', 'MYLES BRAND HALL', ARRAY[]::TEXT[], 'The basic structure of information representation in digital information systems. Begins with low-level computer representations such as common character and numeric encodings. Introduces formal design and query languages through Entity Relationship Modeling, the Relational Model, XML, and XHTML. Laboratory topics include SQL and XPath querying.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 308', 'INFORMATION REPRESENTATION', '5690', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'I E150', 'Michal Gordon', 38, NULL, 'Lecture', '3', 'MYLES BRAND HALL', ARRAY[]::TEXT[], 'The basic structure of information representation in digital information systems. Begins with low-level computer representations such as common character and numeric encodings. Introduces formal design and query languages through Entity Relationship Modeling, the Relational Model, XML, and XHTML. Laboratory topics include SQL and XPath querying.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 308', 'INFORMATION REPRESENTATION', '6549', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'I E150', 'Michal Gordon', 6, NULL, 'Lecture', '3', 'MYLES BRAND HALL', ARRAY[]::TEXT[], 'The basic structure of information representation in digital information systems. Begins with low-level computer representations such as common character and numeric encodings. Introduces formal design and query languages through Entity Relationship Modeling, the Relational Model, XML, and XHTML. Laboratory topics include SQL and XPath querying.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 308', 'INFORMATION REPRESENTATION', '33915', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'I E150', 'Michal Gordon', 35, NULL, 'Lecture', '3', 'MYLES BRAND HALL', ARRAY[]::TEXT[], 'The basic structure of information representation in digital information systems. Begins with low-level computer representations such as common character and numeric encodings. Introduces formal design and query languages through Entity Relationship Modeling, the Relational Model, XML, and XHTML. Laboratory topics include SQL and XPath querying.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 310', 'MULTIMEDIA ARTS AND TECHNOLOGY', '3200', 'Class Status', 'MW Monday, Wednesday 10:10 AM–11:25 AM', 'PY 226', 'Jenny El-Shamy', 38, 'Lecture', 'Lecture', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'The study of the evolution of media arts and underlying principles of communication. Application development paradigms in current practice.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 310', 'MULTIMEDIA ARTS AND TECHNOLOGY', '3258', 'Class Status', 'Th Thursday 5:20 PM–6:10 PM', 'IF 1019', 'Staff', 12, 'Laboratory', 'Lecture', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'The study of the evolution of media arts and underlying principles of communication. Application development paradigms in current practice.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 310', 'MULTIMEDIA ARTS AND TECHNOLOGY', '3259', 'Class Status', 'Th Thursday 6:30 PM–7:20 PM', 'IF 1019', 'Staff', 26, 'Laboratory', 'Lecture', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'The study of the evolution of media arts and underlying principles of communication. Application development paradigms in current practice.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 311', 'APPLICATION DEVELOPMENT', '8510', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'IF 0006', 'J Duncan', 3, 'Lecture', 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'This undergraduate course uses a professional development environment to teach advanced programming skills using an object oriented programming language. Topics include primitive data types, mathematical functions, string manipulation, arrays, logical statements, loops, methods, classes, inheritance, debugging, exception handling, graphical user interfaces (GUIs), and version control software.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 311', 'APPLICATION DEVELOPMENT', '8511', 'Class Status', 'F Friday 11:30 AM–12:45 PM', 'IF 0006', 'Staff', 3, 'Laboratory', 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'This undergraduate course uses a professional development environment to teach advanced programming skills using an object oriented programming language. Topics include primitive data types, mathematical functions, string manipulation, arrays, logical statements, loops, methods, classes, inheritance, debugging, exception handling, graphical user interfaces (GUIs), and version control software.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 341', 'PROTOTYPING WITH ARDUINO TOOLS', '9395', 'Closed', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'IF 4010', 'Matthew Francisco', 0, NULL, 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'The course covers material culture and literature of the hobby and professional electronics design communities with the goal of creating a physical prototype that communicates the students'' creative and social vision. These student prototypes are model systems that embody the computational and organizational thinking of working effectively within engineering firms.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 341', 'PROTOTYPING WITH ARDUINO TOOLS', '9396', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'IF 4010', 'Matthew Francisco', 0, NULL, 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'The course covers material culture and literature of the hobby and professional electronics design communities with the goal of creating a physical prototype that communicates the students'' creative and social vision. These student prototypes are model systems that embody the computational and organizational thinking of working effectively within engineering firms.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 345', 'INTERACTION DESIGN RESEARCH', '34315', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'IF 4063', 'James Clawson', 8, NULL, 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'Students will learn the basics of user experience (UX), including theories of experience, UX data collection, and data analysis methods. It also covers fundamental research topics, including research ethics, sampling, and documentation. Students will translate research results into design: experience journey maps, personas, scenarios, and design concepts.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 360', 'WEB DESIGN', '8375', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'AC C102', 'Erika Lee', 1, NULL, 'Lecture', '3', 'CEDAR HALL', ARRAY[]::TEXT[], 'Hands-on introduction to the core standards required for professional front-end web design and development (HTML/CSS/Bootstrap). You will create websites, plus learn how web content and style work together, how to make professional choices about web graphics and layout, and how to analyze and critique a website''s design and structure.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 360', 'WEB DESIGN', '7977', 'Closed', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'AC C102', 'Erika Lee', 0, NULL, 'Lecture', '3', 'CEDAR HALL', ARRAY[]::TEXT[], 'Hands-on introduction to the core standards required for professional front-end web design and development (HTML/CSS/Bootstrap). You will create websites, plus learn how web content and style work together, how to make professional choices about web graphics and layout, and how to analyze and critique a website''s design and structure.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 363', 'VISUAL DESIGN FOR THE WEB', '11274', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'IF 0117', 'Jenny El-Shamy', 0, NULL, 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'Active learning-based introduction to visual and graphic design. We will first learn how to evaluate design, take better photographs, select appropriate content, and edit and manipulate images. Then we will apply and practice with these concepts to sketch, draw and illustrate digital design compositions and interfaces.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 363', 'VISUAL DESIGN FOR THE WEB', '36764', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'I 107', 'Jenny El-Shamy', 0, NULL, 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'Active learning-based introduction to visual and graphic design. We will first learn how to evaluate design, take better photographs, select appropriate content, and edit and manipulate images. Then we will apply and practice with these concepts to sketch, draw and illustrate digital design compositions and interfaces.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 365', 'JAVASCRIPT', '11275', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'SB 015', 'Erika Lee', 27, NULL, 'Lecture', '3', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], 'Hands-on, project-based JavaScript programming course with a focus on creating interactive web interfaces. Goal is to integrate JavaScript with HTML, CSS and responsive web design techniques in order to capture and respond, both visually and programmatically, to a variety of user interactions and data inputs, including APIs.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 368', 'INTRODUCTION TO NETWORK SCIENCE', '6987', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'IF 1104', 'Filippo Menczer', 1, NULL, 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'Friends, computers, the Web, and our brain are examples of networks that pervade our lives. Network science helps us understand complex patterns of connection, interaction, and relationships in many complex systems. Students learn essential concepts and core ideas of network literacy, and basic tools to handle social and information networks.', ARRAY['Class uses IU eTexts'], NULL),
    ('INFO-I 369', 'PERFORMANCE ANALYTICS', '11061', 'Class Status', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'I E130', 'Filippo Radicchi', 17, NULL, 'Lecture', '3', 'MYLES BRAND HALL', ARRAY[]::TEXT[], 'This course will review quantitative studies aimed at measuring, predicting and understanding performance in social competitive arenas, ranging from social media to financial markets, from professional sports to scientific and technological innovation.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 370', 'METHODS FOR HCC', '8512', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'GA 1106', 'Eli Blevis', 42, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'UX/UI Design uses a variety of approaches for obtaining human-centered information and requirements for the design and development of systems and applications. The course surveys key methods, current and emergent, in the field of Human Computer Interaction and Interaction Design to prepare students for a career in IT.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 389', 'SERVE IT INTERNSHIP IN INFORMATICS', '10373', 'Class Status', NULL, NULL, 'Una Thacker', 58, NULL, 'Lecture', '1–3', NULL, ARRAY[]::TEXT[], 'The Serve IT Internship offers students civic and professional working experience in an industry setting using skills acquired in informatics coursework to meet needs in the community through a service-learning experience.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 390', 'UNDERGRADUATE INDEPENDENT STUDY', '13134', 'Class Status', NULL, NULL, 'Matthew Francisco', 19, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Independent research based on existing literature or original work. A report, in the style of a departmental technical report, is required.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 390', 'UNDERGRADUATE INDEPENDENT STUDY', '7129', 'Class Status', NULL, NULL, 'Tiana Iruoje, Paul Macklin', 14, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Independent research based on existing literature or original work. A report, in the style of a departmental technical report, is required.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 391', 'PROFESSIONAL INTERNSHIP', '3180', 'Class Status', NULL, NULL, 'Matthew Francisco, Rebekah Sinders', 28, NULL, 'Internship', '1–3', NULL, ARRAY[]::TEXT[], 'Students gain professional work experience in an industry or research organization setting, using skills and knowledge acquired in informatics course work.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 391', 'PROFESSIONAL INTERNSHIP', '4411', 'Class Status', NULL, NULL, 'Matthew Francisco, Rebekah Sinders', 30, NULL, 'Internship', '1–3', NULL, ARRAY[]::TEXT[], 'Students gain professional work experience in an industry or research organization setting, using skills and knowledge acquired in informatics course work.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 399', 'CURRENT TOPICS IN INFORMATICS', '9390', 'Class Status', 'MW Monday, Wednesday 12:45 PM–3:00 PM', 'AC C102', 'Daniel Pierz', 1, NULL, 'Lecture', '1–3', 'CEDAR HALL', ARRAY[]::TEXT[], 'Variable topics. Emphasis is on new developments and research in informatics.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 399', 'CURRENT TOPICS IN INFORMATICS', '8666', 'Class Status', NULL, 'WB WEB', 'Madeleine Gonin, Akesha Horton', 2, NULL, 'Lecture', '1–3', 'CEDAR HALL', ARRAY[]::TEXT[], 'Variable topics. Emphasis is on new developments and research in informatics.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 399', 'CURRENT TOPICS IN INFORMATICS', '8376', 'Closed', 'MW Monday, Wednesday 12:45 PM–3:00 PM', 'AC C102', 'Daniel Pierz', 0, NULL, 'Lecture', '1–3', 'CEDAR HALL', ARRAY[]::TEXT[], 'Variable topics. Emphasis is on new developments and research in informatics.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 400', 'TOPICS IN INFORMATICS', '11607', 'Class Status', 'M Monday 6:40 PM–8:40 PM', 'GA 1112', 'David Wild, Isak Nti Asare', 15, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Variable topics. Emphasis is on new developments and research in informatics.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 400', 'TOPICS IN INFORMATICS', '31505', 'Class Status', 'TuTh Tuesday, Thursday 5:30 PM–6:45 PM', 'I E130', 'Umair Malik', 26, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Variable topics. Emphasis is on new developments and research in informatics.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 400', 'TOPICS IN INFORMATICS', '10327', 'Closed', 'MW Monday, Wednesday 8:00 AM–9:15 AM', 'IF 1019', 'Chase McCoy', 0, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Variable topics. Emphasis is on new developments and research in informatics.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 400', 'TOPICS IN INFORMATICS', '10637', 'Closed', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'GY 1050', 'Kayce Reed-Buechlein', 0, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Variable topics. Emphasis is on new developments and research in informatics.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 403', 'MOBILE HUMAN COMPUTER INTERACTION AND DESIGN', '34319', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'SY 103', 'James Clawson', 3, NULL, 'Lecture', '3', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'This course takes a human-centered design approach to engage students in creating cutting edge mobile and wearable systems. Through a semester long project, students identify challenges/barriers/obstacles encountered by individuals and/or groups in their everyday lives and then design, prototype, and evaluate solutions to those challenges.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 411', 'ANIMAL-COMPUTER INTERACTION METHODS', '10043', 'Class Status', 'M Monday 7:05 PM–8:25 PM', 'I E130', 'Christopher Martin', 3, 'Lecture', 'Lecture', '3', 'MYLES BRAND HALL', ARRAY[]::TEXT[], 'This courses introduces cutting-edge Animal-Computer Interaction methods with a focus on how they are used to enhance animal welfare, enrichment, husbandry, and cognitive research opportunities. It will also take a critical approach and consider key challenges relating to access, ethics, implementation, scale, and evaluation of ACI methods.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 411', 'ANIMAL-COMPUTER INTERACTION METHODS', '11058', 'Class Status', 'W Wednesday 8:05 PM–9:25 PM', 'I 109', 'Christopher Martin', 3, 'Laboratory', 'Lecture', '3', 'MYLES BRAND HALL', ARRAY[]::TEXT[], 'This courses introduces cutting-edge Animal-Computer Interaction methods with a focus on how they are used to enhance animal welfare, enrichment, husbandry, and cognitive research opportunities. It will also take a critical approach and consider key challenges relating to access, ethics, implementation, scale, and evaluation of ACI methods.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 414', 'SEMINAR ON TECH FOR ANIMALS', '10051', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:15 PM', 'I 107', 'Christena Nippert-Eng', 21, NULL, 'Seminar', '3', 'MYLES BRAND HALL', ARRAY[]::TEXT[], 'This exploratory seminar is an introduction to ACI. We will draw on faculty and student selected readings, multimedia materials, and guest lectures from current ACI practitioners to see what we think about the ethics, history, state-of-the art, and possible futures for this broad field of practice.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 422', 'DATA VISUALIZATION', '14023', 'Class Status', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'GA 1128', 'Alex Leykin', 4, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'From dashboards in a car to cutting-edge scientific papers, we extensively use visual representation of data. As our world becomes increasingly connected and digitized and as more decisions are being driven by data, data visualization is becoming a critical skill for every knowledge worker. In this course we will learn fundamentals of data visualization and create visualizations that can provide insights into complex datasets.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 430', 'SECURITY FOR NETWORKED SYSTEMS', '7066', 'Class Status', 'MW Monday, Wednesday 11:35 AM–12:25 PM', 'FA 102', 'Dongfang Zhao', 9, 'Lecture', 'Lecture', '3', 'FINE ARTS', ARRAY[]::TEXT[], 'An extensive survey of network security. Covers threats to information confidentiality, integrity, and availability in different Internet layers, and defense mechanisms which control these threats. Also provides a necessary foundation on network security, such as cryptographic primitives/protocols, authentication, authorization, and access control technologies. Hands-on experiences through programming assignments and course projects.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 430', 'SECURITY FOR NETWORKED SYSTEMS', '7067', 'Class Status', 'Th Thursday 9:35 AM–10:50 AM', 'IF 3115', 'Staff', 2, 'Laboratory', 'Lecture', '3', 'FINE ARTS', ARRAY[]::TEXT[], 'An extensive survey of network security. Covers threats to information confidentiality, integrity, and availability in different Internet layers, and defense mechanisms which control these threats. Also provides a necessary foundation on network security, such as cryptographic primitives/protocols, authentication, authorization, and access control technologies. Hands-on experiences through programming assignments and course projects.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 430', 'SECURITY FOR NETWORKED SYSTEMS', '35041', 'Class Status', 'Th Thursday 2:20 PM–3:35 PM', 'IF 3115', 'Dongfang Zhao', 8, 'Laboratory', 'Lecture', '3', 'FINE ARTS', ARRAY[]::TEXT[], 'An extensive survey of network security. Covers threats to information confidentiality, integrity, and availability in different Internet layers, and defense mechanisms which control these threats. Also provides a necessary foundation on network security, such as cryptographic primitives/protocols, authentication, authorization, and access control technologies. Hands-on experiences through programming assignments and course projects.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 430', 'SECURITY FOR NETWORKED SYSTEMS', '8093', 'Closed', 'Th Thursday 11:10 AM–12:25 PM', 'IF 3115', 'Staff', 0, 'Laboratory', 'Lecture', '3', 'FINE ARTS', ARRAY[]::TEXT[], 'An extensive survey of network security. Covers threats to information confidentiality, integrity, and availability in different Internet layers, and defense mechanisms which control these threats. Also provides a necessary foundation on network security, such as cryptographic primitives/protocols, authentication, authorization, and access control technologies. Hands-on experiences through programming assignments and course projects.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 430', 'SECURITY FOR NETWORKED SYSTEMS', '11898', 'Closed', 'Th Thursday 12:45 PM–2:00 PM', 'IF 3115', 'Dongfang Zhao', 0, 'Laboratory', 'Lecture', '3', 'FINE ARTS', ARRAY[]::TEXT[], 'An extensive survey of network security. Covers threats to information confidentiality, integrity, and availability in different Internet layers, and defense mechanisms which control these threats. Also provides a necessary foundation on network security, such as cryptographic primitives/protocols, authentication, authorization, and access control technologies. Hands-on experiences through programming assignments and course projects.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 440', 'HUMAN ROBOT INTERACTION', '9397', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'I E130', 'Selma Sabanovic', 0, NULL, 'Lecture', '3', 'MYLES BRAND HALL', ARRAY[]::TEXT[], 'This course surveys the field of human-robot interaction (HRI), which involves understanding how people perceive and respond to robots and creating robots that interact naturally with people. We will discuss the design, evaluation and societal significance of interactive robots from a human-centered perspective through readings, discussion and developing HRI prototypes.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 441', 'INTERACTION DESIGN PRACTICE', '14139', 'Closed', 'MW Monday, Wednesday 5:30 PM–6:45 PM', 'I 107', 'Martin Siegel', 0, NULL, 'Lecture', '3', 'MYLES BRAND HALL', ARRAY[]::TEXT[], 'Human-computer interaction design (HCID) describes the way a person or group accomplishes tasks with a computer - what the individual or group does and how the computer responds; what the computer does and how the individual or group responds. This course will be organized a collection of readings and three design projects applying human-computer interaction principles to the design, selection, and evaluation of interactive systems.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 443', 'BUILDING VIRTUAL WORLDS', '34494', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'IF 4063', 'Joshua McGraw', 7, NULL, 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'This course will explore advanced techniques for designing and building virtual reality worlds. Topics include rigged animation, spatial sound, keyframe and procedural animation, interactivity, intelligent cameras, advanced shaders, and particle systems. Students will develop proficiency with a variety of software tools, development methods, and creation techniques.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 453', 'COMPUTER AND INFORMATION ETHICS', '4412', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'IF 0117', 'Alexis Peirce Caudell', 0, NULL, 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'Ethical and professional issues that arise in the context of designing and using networked information technologies and information resources. Examines frameworks for making ethical decisions, emergent technologies and their ethical implications, information/computer professionalism. Topics include privacy, intellectual property, cybercrime, games, social justice, and codes of professional ethics.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 453', 'COMPUTER AND INFORMATION ETHICS', '6482', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'BH 008', 'Jacob Boss', 0, NULL, 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'Ethical and professional issues that arise in the context of designing and using networked information technologies and information resources. Examines frameworks for making ethical decisions, emergent technologies and their ethical implications, information/computer professionalism. Topics include privacy, intellectual property, cybercrime, games, social justice, and codes of professional ethics.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 453', 'COMPUTER AND INFORMATION ETHICS', '6917', 'Closed', 'MW Monday, Wednesday 5:30 PM–6:45 PM', 'I E150', 'John Paolillo', 0, NULL, 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'Ethical and professional issues that arise in the context of designing and using networked information technologies and information resources. Examines frameworks for making ethical decisions, emergent technologies and their ethical implications, information/computer professionalism. Topics include privacy, intellectual property, cybercrime, games, social justice, and codes of professional ethics.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 457', 'IMMERSIVE STORYTELLING AND EXPERIENCE DESIGN', '13498', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:15 PM', 'I E150', 'Jennifer Terrell', 11, NULL, 'Lecture', '3', 'MYLES BRAND HALL', ARRAY[]::TEXT[], 'Students examine the role of technology in immersive storytelling in themed entertainment settings (theme parks, zoos, museums, etc) and practice designing their own story-based attraction. Special attention is paid to understanding the creation of emotion and designing for audience experience, considering the use of computational technologies in this context.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 487', 'INTRODUCTION TO VIRTUAL HERITAGE', '9770', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:30 PM', 'IF 1019', 'Gabriele Guidi', 5, NULL, 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'This course focuses on how digital technology can represent, restore, disseminate, and help with analysis of artifacts such as vases, furniture, sculpture, monuments, and buildings. Other topics covered include the history and methodologies of Virtual Heritage. Each semester a different case study will provide the focus for the course.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 489', 'SERVE IT CAPSTONE INTERNSHIP INFORMATICS', '10374', 'Class Status', NULL, NULL, 'Una Thacker', 41, NULL, 'Lecture', '3–6', NULL, ARRAY[]::TEXT[], 'The Serve IT Capstone Internship offers students civic and professional working experience in an industry setting using skills acquired in informatics coursework to meet needs in the community through the development of a substantial project in a service-learning experience.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 490', 'PROFESSIONAL INTERNSHIP (NOT FOR CREDIT)', '4252', 'Class Status', NULL, NULL, 'Matthew Francisco, Rebekah Sinders', 10, NULL, 'Internship', '0', NULL, ARRAY[]::TEXT[], 'Students gain professional work experience in an industry or research organization setting, using skills and knowledge acquired in informatics coursework.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 490', 'PROFESSIONAL INTERNSHIP (NOT FOR CREDIT)', '4413', 'Class Status', NULL, NULL, 'Matthew Francisco, Rebekah Sinders', 8, NULL, 'Internship', '0', NULL, ARRAY[]::TEXT[], 'Students gain professional work experience in an industry or research organization setting, using skills and knowledge acquired in informatics coursework.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 491', 'CAPSTONE PROJECT INTERNSHIP', '3181', 'Class Status', NULL, NULL, 'Matthew Francisco, Rebekah Sinders', 24, NULL, 'Internship', '1–9', NULL, ARRAY[]::TEXT[], 'This course provides students with hands-on experience in a professional informatics environment, allowing them to apply theoretical knowledge, develop technical skills, and gain exposure to industry practices. Students put their informatics education in practice through the development of a substantial project while working in a professional information technology environment.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 491', 'CAPSTONE PROJECT INTERNSHIP', '4414', 'Class Status', NULL, NULL, 'Matthew Francisco, Rebekah Sinders', 27, NULL, 'Internship', '1–9', NULL, ARRAY[]::TEXT[], 'This course provides students with hands-on experience in a professional informatics environment, allowing them to apply theoretical knowledge, develop technical skills, and gain exposure to industry practices. Students put their informatics education in practice through the development of a substantial project while working in a professional information technology environment.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 492', 'SENIOR THESIS', '2036', 'Class Status', NULL, NULL, 'Matthew Francisco', 6, NULL, 'Research', '3', NULL, ARRAY[]::TEXT[], 'The senior student prepares and presents a thesis: a substantial, typically multi-chapter paper based on a well-planned research or scholarly project, as worked out between a student and a sponsoring faculty member.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 492', 'SENIOR THESIS', '4415', 'Class Status', NULL, NULL, 'Matthew Francisco', 10, NULL, 'Research', '3', NULL, ARRAY[]::TEXT[], 'The senior student prepares and presents a thesis: a substantial, typically multi-chapter paper based on a well-planned research or scholarly project, as worked out between a student and a sponsoring faculty member.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 493', 'SENIOR THESIS', '2037', 'Class Status', NULL, NULL, 'Matthew Francisco', 9, NULL, 'Research', '3', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('INFO-I 493', 'SENIOR THESIS', '4416', 'Class Status', NULL, NULL, 'Matthew Francisco', 10, NULL, 'Research', '3', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('INFO-I 494', 'DESIGN AND IMPLEMENTATION OF AN INFORMATION SYSTEM (PART I)', '2035', 'Class Status', 'M Monday 3:55 PM–5:10 PM', 'JH 124', 'LJ Paul, Alexis Peirce Caudell', 47, 'Lecture', 'Lecture', '3', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'Students work on capstone projects in supervised teams. They select an appropriate project (preferably based on cognate) and then learn to develop a plan that leads to success. Teamwork, communication, and organizational skills are emphasized in a real-world-style environment. Credit not given for both INFO-I 494 and H 494.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 494', 'DESIGN AND IMPLEMENTATION OF AN INFORMATION SYSTEM (PART I)', '11059', 'Class Status', 'W Wednesday 3:55 PM–5:10 PM', 'IF 1106', 'Staff', 14, 'Practice', 'Lecture', '3', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'Students work on capstone projects in supervised teams. They select an appropriate project (preferably based on cognate) and then learn to develop a plan that leads to success. Teamwork, communication, and organizational skills are emphasized in a real-world-style environment. Credit not given for both INFO-I 494 and H 494.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 494', 'DESIGN AND IMPLEMENTATION OF AN INFORMATION SYSTEM (PART I)', '11060', 'Class Status', 'W Wednesday 3:55 PM–5:10 PM', 'LU 1001', 'Staff', 33, 'Practice', 'Lecture', '3', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'Students work on capstone projects in supervised teams. They select an appropriate project (preferably based on cognate) and then learn to develop a plan that leads to success. Teamwork, communication, and organizational skills are emphasized in a real-world-style environment. Credit not given for both INFO-I 494 and H 494.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 494', 'DESIGN AND IMPLEMENTATION OF AN INFORMATION SYSTEM (PART I)', '36824', 'Class Status', 'M Monday 3:55 PM–5:10 PM', 'JH 124', 'LJ Paul, Alexis Peirce Caudell', 47, 'Lecture', 'Lecture', '3', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'Students work on capstone projects in supervised teams. They select an appropriate project (preferably based on cognate) and then learn to develop a plan that leads to success. Teamwork, communication, and organizational skills are emphasized in a real-world-style environment. Credit not given for both INFO-I 494 and H 494.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 498', 'CAPSTONE COOPERATIVE EXPERIENCE', '15163', 'Class Status', NULL, NULL, 'Matthew Francisco, Rebekah Sinders', 18, NULL, 'Internship', '1–6', NULL, ARRAY[]::TEXT[], 'Students put their informatics education in practice through the development of a substantial project while working in a professional information technology environment with the guidance/mentorship of a faculty member. May be repeated for a maximum of 6 credit hours.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 499', 'READINGS AND RESEARCH IN INFORMATICS', '2038', 'Class Status', NULL, NULL, 'Matthew Francisco', 9, NULL, 'Research', '1–3', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('INFO-I 499', 'READINGS AND RESEARCH IN INFORMATICS', '4417', 'Class Status', NULL, NULL, 'Matthew Francisco', 10, NULL, 'Research', '1–3', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('INFO-I 500', 'FUNDAMENTAL COMPUTER CONCEPTS FOR INFORMATICS', '7162', 'Class Status', 'TuTh Tuesday, Thursday 7:05 PM–8:20 PM', 'IF 1106', 'Sakher Qaaidi', 5, 'Lecture', 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'An introduction to fundamental principles of computer concepts for Informatics study, including an overview of computer architecture, computer algorithms, fundamentals of operating systems, data structure, file organization and database concepts.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 500', 'FUNDAMENTAL COMPUTER CONCEPTS FOR INFORMATICS', '7163', 'Class Status', 'F Friday 10:20 AM–11:10 AM', 'I 109', 'Staff', 5, 'Laboratory', 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'An introduction to fundamental principles of computer concepts for Informatics study, including an overview of computer architecture, computer algorithms, fundamentals of operating systems, data structure, file organization and database concepts.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 501', 'INTRODUCTION TO INFORMATICS', '7096', 'Class Status', 'W Wednesday 11:35 AM–2:10 PM', 'JH A106', 'Stasa Milojevic', 7, NULL, 'Lecture', '3', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'The course deals with the foundations of Informatics as an interdisciplinary field. We will study concepts such as Information, Technology, Knowledge, Modeling, and their impact on science and society. The course will also attempt to define and understand what computational and systems thinking can bring to science and society.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 511', 'ANIMAL-COMPUTER INTERACTION METHODS', '10085', 'Class Status', 'M Monday 7:05 PM–8:25 PM', 'I E130', 'Christopher Martin', 3, 'Lecture', 'Lecture', '3', 'MYLES BRAND HALL', ARRAY[]::TEXT[], 'This courses introduces cutting-edge Animal-Computer Interaction methods with a focus on how they are used to enhance animal welfare, enrichment, husbandry, and cognitive research opportunities. It will also take a critical approach and consider key challenges relating to access, ethics, implementation, scale, and evaluation of ACI methods.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 511', 'ANIMAL-COMPUTER INTERACTION METHODS', '11057', 'Class Status', 'W Wednesday 8:05 PM–9:25 PM', 'I 109', 'Christopher Martin', 3, 'Laboratory', 'Lecture', '3', 'MYLES BRAND HALL', ARRAY[]::TEXT[], 'This courses introduces cutting-edge Animal-Computer Interaction methods with a focus on how they are used to enhance animal welfare, enrichment, husbandry, and cognitive research opportunities. It will also take a critical approach and consider key challenges relating to access, ethics, implementation, scale, and evaluation of ACI methods.', ARRAY[]::TEXT[], NULL)
